export const versesByEmotion: Record<string, CuratedVerse[]> = {"sad":[{"id":"sad-psalm-34-18","reference":"Psalm 34:18","text":"The Lord is nigh unto them that are of a broken heart; and saveth such as be of a contrite spirit.","reflection":"God is not far when your heart is shattered. He draws close to the brokenhearted — not away from them.","emotion":"sad","book":"Psalms","chapter":34,"verseStart":18,"verseEnd":18},{"id":"sad-psalm-30-5","reference":"Psalm 30:5","text":"For his anger endureth but a moment; in his favour is life: weeping may endure for a night, but joy cometh in the morning.","reflection":"Your tears are real, but they are not the final word. A new morning — and new joy — is always coming.","emotion":"sad","book":"Psalms","chapter":30,"verseStart":5,"verseEnd":5},{"id":"sad-psalm-147-3","reference":"Psalm 147:3","text":"He healeth the broken in heart, and bindeth up their wounds.","reflection":"God is a healer, not just of bodies but of broken hearts. He tends your wounds with care.","emotion":"sad","book":"Psalms","chapter":147,"verseStart":3,"verseEnd":3},{"id":"sad-psalm-55-22","reference":"Psalm 55:22","text":"Cast thy burden upon the Lord, and he shall sustain thee: he shall never suffer the righteous to be moved.","reflection":"You were never meant to carry your grief alone. Place it in His hands and He will hold you up.","emotion":"sad","book":"Psalms","chapter":55,"verseStart":22,"verseEnd":22},{"id":"sad-john-11-35","reference":"John 11:35","text":"Jesus wept.","reflection":"The shortest verse in the Bible carries a deep truth — Jesus is moved by your pain. He weeps with you.","emotion":"sad","book":"John","chapter":11,"verseStart":35,"verseEnd":35},{"id":"sad-matthew-5-4","reference":"Matthew 5:4","text":"Blessed are they that mourn: for they shall be comforted.","reflection":"Jesus calls the mourning \"blessed\" — not because sorrow is good, but because comfort is coming.","emotion":"sad","book":"Matthew","chapter":5,"verseStart":4,"verseEnd":4},{"id":"sad-psalm-42-11","reference":"Psalm 42:11","text":"Why art thou cast down, O my soul? and why art thou disquieted within me? hope thou in God: for I shall yet praise him, who is the health of my countenance, and my God.","reflection":"Even when your soul feels cast down, you can still speak hope to it: God is worth waiting for.","emotion":"sad","book":"Psalms","chapter":42,"verseStart":11,"verseEnd":11},{"id":"sad-revelation-21-4","reference":"Revelation 21:4","text":"And God shall wipe away all tears from their eyes; and there shall be no more death, neither sorrow, nor crying, neither shall there be any more pain: for the former things are passed away.","reflection":"A day is coming when God Himself wipes every tear away, and sorrow has no place left to live.","emotion":"sad","book":"Revelation","chapter":21,"verseStart":4,"verseEnd":4},{"id":"sad-2-corinthians-1-3-4","reference":"2 Corinthians 1:3-4","text":"Blessed be God, even the Father of our Lord Jesus Christ, the Father of mercies, and the God of all comfort; Who comforteth us in all our tribulation, that we may be able to comfort them which are in any trouble, by the comfort wherewith we ourselves are comforted of God.","reflection":"God is the source of all comfort — and the comfort He gives you can one day flow through you to others.","emotion":"sad","book":"2 Corinthians","chapter":1,"verseStart":3,"verseEnd":4},{"id":"sad-psalm-56-8","reference":"Psalm 56:8","text":"Thou tellest my wanderings: put thou my tears into thy bottle: are they not in thy book?","reflection":"God keeps count of your sorrows and stores your tears. Not one of them is wasted or unseen.","emotion":"sad","book":"Psalms","chapter":56,"verseStart":8,"verseEnd":8},{"id":"sad-psalm-126-5","reference":"Psalm 126:5","text":"They that sow in tears shall reap in joy.","reflection":"The tears you sow in this hard season are not the end of the story — a harvest of joy is promised.","emotion":"sad","book":"Psalms","chapter":126,"verseStart":5,"verseEnd":5},{"id":"sad-john-16-22","reference":"John 16:22","text":"And ye now therefore have sorrow: but I will see you again, and your heart shall rejoice, and your joy no man taketh from you.","reflection":"The grief you feel now is real, but Jesus promises a joy that no one will ever take from you.","emotion":"sad","book":"John","chapter":16,"verseStart":22,"verseEnd":22},{"id":"sad-isaiah-53-3","reference":"Isaiah 53:3","text":"He is despised and rejected of men; a man of sorrows, and acquainted with grief: and we hid as it were our faces from him; he was despised, and we esteemed him not.","reflection":"Jesus was \"a man of sorrows, acquainted with grief.\" He understands exactly where you are.","emotion":"sad","book":"Isaiah","chapter":53,"verseStart":3,"verseEnd":3}],"grief":[{"id":"grief-psalm-23-4","reference":"Psalm 23:4","text":"Yea, though I walk through the valley of the shadow of death, I will fear no evil: for thou art with me; thy rod and thy staff they comfort me.","reflection":"Even in the valley of the shadow of death, you are not walking alone — the Shepherd is with you.","emotion":"grief","book":"Psalms","chapter":23,"verseStart":4,"verseEnd":4},{"id":"grief-john-11-25-26","reference":"John 11:25-26","text":"Jesus said unto her, I am the resurrection, and the life: he that believeth in me, though he were dead, yet shall he live: And whosoever liveth and believeth in me shall never die. Believest thou this?","reflection":"Jesus is the resurrection and the life. Death is not the final goodbye for those who are His.","emotion":"grief","book":"John","chapter":11,"verseStart":25,"verseEnd":26},{"id":"grief-revelation-21-4","reference":"Revelation 21:4","text":"And God shall wipe away all tears from their eyes; and there shall be no more death, neither sorrow, nor crying, neither shall there be any more pain: for the former things are passed away.","reflection":"There is a future with no more death, no more crying, no more pain. God promises it Himself.","emotion":"grief","book":"Revelation","chapter":21,"verseStart":4,"verseEnd":4},{"id":"grief-1-thessalonians-4-13-14","reference":"1 Thessalonians 4:13-14","text":"But I would not have you to be ignorant, brethren, concerning them which are asleep, that ye sorrow not, even as others which have no hope. For if we believe that Jesus died and rose again, even so them also which sleep in Jesus will God bring with him.","reflection":"Christians grieve — but not as those without hope. Death is not the end for those in Christ.","emotion":"grief","book":"1 Thessalonians","chapter":4,"verseStart":13,"verseEnd":14},{"id":"grief-2-corinthians-1-3-4","reference":"2 Corinthians 1:3-4","text":"Blessed be God, even the Father of our Lord Jesus Christ, the Father of mercies, and the God of all comfort; Who comforteth us in all our tribulation, that we may be able to comfort them which are in any trouble, by the comfort wherewith we ourselves are comforted of God.","reflection":"God is the Father of mercies and the God of all comfort, near to you in your mourning.","emotion":"grief","book":"2 Corinthians","chapter":1,"verseStart":3,"verseEnd":4},{"id":"grief-psalm-34-18","reference":"Psalm 34:18","text":"The Lord is nigh unto them that are of a broken heart; and saveth such as be of a contrite spirit.","reflection":"God draws especially near to the broken — your shattered heart is not too much for Him.","emotion":"grief","book":"Psalms","chapter":34,"verseStart":18,"verseEnd":18},{"id":"grief-psalm-73-26","reference":"Psalm 73:26","text":"My flesh and my heart faileth: but God is the strength of my heart, and my portion for ever.","reflection":"Even when everything in you fails, God remains your strength and your portion forever.","emotion":"grief","book":"Psalms","chapter":73,"verseStart":26,"verseEnd":26},{"id":"grief-john-14-1-3","reference":"John 14:1-3","text":"Let not your heart be troubled: ye believe in God, believe also in me. In my Father’s house are many mansions: if it were not so, I would have told you. I go to prepare a place for you. And if I go and prepare a place for you, I will come again, and receive you unto myself; that where I am, there ye may be also.","reflection":"Jesus has gone to prepare a place. Let this steady your troubled heart in the days of loss.","emotion":"grief","book":"John","chapter":14,"verseStart":1,"verseEnd":3},{"id":"grief-romans-8-38-39","reference":"Romans 8:38-39","text":"For I am persuaded, that neither death, nor life, nor angels, nor principalities, nor powers, nor things present, nor things to come, Nor height, nor depth, nor any other creature, shall be able to separate us from the love of God, which is in Christ Jesus our Lord.","reflection":"Not even death can separate you — or those who died in Christ — from the love of God.","emotion":"grief","book":"Romans","chapter":8,"verseStart":38,"verseEnd":39},{"id":"grief-psalm-116-15","reference":"Psalm 116:15","text":"Precious in the sight of the Lord is the death of his saints.","reflection":"The death of God’s people is precious in His sight. Your loved one is not forgotten by Him.","emotion":"grief","book":"Psalms","chapter":116,"verseStart":15,"verseEnd":15},{"id":"grief-isaiah-25-8","reference":"Isaiah 25:8","text":"He will swallow up death in victory; and the Lord God will wipe away tears from off all faces; and the rebuke of his people shall he take away from off all the earth: for the Lord hath spoken it.","reflection":"God will swallow up death forever and wipe the tears from all faces. Grief has an expiry date.","emotion":"grief","book":"Isaiah","chapter":25,"verseStart":8,"verseEnd":8},{"id":"grief-lamentations-3-31-32","reference":"Lamentations 3:31-32","text":"For the Lord will not cast off for ever: But though he cause grief, yet will he have compassion according to the multitude of his mercies.","reflection":"God does not cast off forever; though He allows grief, He shows compassion in great measure.","emotion":"grief","book":"Lamentations","chapter":3,"verseStart":31,"verseEnd":32},{"id":"grief-matthew-5-4","reference":"Matthew 5:4","text":"Blessed are they that mourn: for they shall be comforted.","reflection":"Blessed are those who mourn, for they shall be comforted — a promise straight from Jesus.","emotion":"grief","book":"Matthew","chapter":5,"verseStart":4,"verseEnd":4}],"lonely":[{"id":"lonely-deuteronomy-31-6","reference":"Deuteronomy 31:6","text":"Be strong and of a good courage, fear not, nor be afraid of them: for the Lord thy God, he it is that doth go with thee; he will not fail thee, nor forsake thee.","reflection":"However abandoned you feel, God has promised He will not leave you. Not now, not ever.","emotion":"lonely","book":"Deuteronomy","chapter":31,"verseStart":6,"verseEnd":6},{"id":"lonely-hebrews-13-5","reference":"Hebrews 13:5","text":"Let your conversation be without covetousness; and be content with such things as ye have: for he hath said, I will never leave thee, nor forsake thee.","reflection":"A direct promise from God to you: \"I will never leave thee, nor forsake thee.\"","emotion":"lonely","book":"Hebrews","chapter":13,"verseStart":5,"verseEnd":5},{"id":"lonely-psalm-68-6","reference":"Psalm 68:6","text":"God setteth the solitary in families: he bringeth out those which are bound with chains: but the rebellious dwell in a dry land.","reflection":"God sees those who are alone and works to bring them into belonging. Isolation is not your home.","emotion":"lonely","book":"Psalms","chapter":68,"verseStart":6,"verseEnd":6},{"id":"lonely-psalm-25-16","reference":"Psalm 25:16","text":"Turn thee unto me, and have mercy upon me; for I am desolate and afflicted.","reflection":"Even David cried out in loneliness. God welcomes this honest prayer — you can pray it too.","emotion":"lonely","book":"Psalms","chapter":25,"verseStart":16,"verseEnd":16},{"id":"lonely-matthew-28-20","reference":"Matthew 28:20","text":"Teaching them to observe all things whatsoever I have commanded you: and, lo, I am with you alway, even unto the end of the world. Amen.","reflection":"Jesus’ last promise before ascending: \"I am with you always.\" Always includes right now.","emotion":"lonely","book":"Matthew","chapter":28,"verseStart":20,"verseEnd":20},{"id":"lonely-psalm-139-7-10","reference":"Psalm 139:7-10","text":"Whither shall I go from thy spirit? or whither shall I flee from thy presence? If I ascend up into heaven, thou art there: if I make my bed in hell, behold, thou art there. If I take the wings of the morning, and dwell in the uttermost parts of the sea; Even there shall thy hand lead me, and thy right hand shall hold me.","reflection":"There is nowhere you can go from God’s presence. Even in the dark, His hand holds you.","emotion":"lonely","book":"Psalms","chapter":139,"verseStart":7,"verseEnd":10},{"id":"lonely-psalm-27-10","reference":"Psalm 27:10","text":"When my father and my mother forsake me, then the Lord will take me up.","reflection":"Even if those closest to you forsake you, the Lord Himself will take you up.","emotion":"lonely","book":"Psalms","chapter":27,"verseStart":10,"verseEnd":10},{"id":"lonely-john-14-18","reference":"John 14:18","text":"I will not leave you comfortless: I will come to you.","reflection":"Jesus says, \"I will not leave you comfortless.\" He does not abandon His own as orphans.","emotion":"lonely","book":"John","chapter":14,"verseStart":18,"verseEnd":18},{"id":"lonely-isaiah-41-10","reference":"Isaiah 41:10","text":"Fear thou not; for I am with thee: be not dismayed; for I am thy God: I will strengthen thee; yea, I will help thee; yea, I will uphold thee with the right hand of my righteousness.","reflection":"You need not fear, for God is with you; He strengthens, helps, and upholds you.","emotion":"lonely","book":"Isaiah","chapter":41,"verseStart":10,"verseEnd":10},{"id":"lonely-psalm-73-23","reference":"Psalm 73:23","text":"Nevertheless I am continually with thee: thou hast holden me by my right hand.","reflection":"Whatever you feel, the truth holds: you are continually with Him, and He holds your right hand.","emotion":"lonely","book":"Psalms","chapter":73,"verseStart":23,"verseEnd":23},{"id":"lonely-joshua-1-9","reference":"Joshua 1:9","text":"Have not I commanded thee? Be strong and of a good courage; be not afraid, neither be thou dismayed: for the Lord thy God is with thee whithersoever thou goest.","reflection":"Be strong and courageous — the Lord your God is with you wherever you go.","emotion":"lonely","book":"Joshua","chapter":1,"verseStart":9,"verseEnd":9},{"id":"lonely-romans-8-38-39","reference":"Romans 8:38-39","text":"For I am persuaded, that neither death, nor life, nor angels, nor principalities, nor powers, nor things present, nor things to come, Nor height, nor depth, nor any other creature, shall be able to separate us from the love of God, which is in Christ Jesus our Lord.","reflection":"Nothing in all creation can separate you from the love of God in Christ Jesus.","emotion":"lonely","book":"Romans","chapter":8,"verseStart":38,"verseEnd":39}],"depressed":[{"id":"depressed-psalm-42-11","reference":"Psalm 42:11","text":"Why art thou cast down, O my soul? and why art thou disquieted within me? hope thou in God: for I shall yet praise him, who is the health of my countenance, and my God.","reflection":"When your soul is cast down, preach to it: hope in God, for you will yet praise Him.","emotion":"depressed","book":"Psalms","chapter":42,"verseStart":11,"verseEnd":11},{"id":"depressed-psalm-34-17","reference":"Psalm 34:17","text":"The righteous cry, and the Lord heareth, and delivereth them out of all their troubles.","reflection":"When the righteous cry out, the Lord hears and delivers them out of all their troubles.","emotion":"depressed","book":"Psalms","chapter":34,"verseStart":17,"verseEnd":17},{"id":"depressed-psalm-40-1-2","reference":"Psalm 40:1-2","text":"I waited patiently for the Lord; and he inclined unto me, and heard my cry. He brought me up also out of an horrible pit, out of the miry clay, and set my feet upon a rock, and established my goings.","reflection":"God lifts us out of the pit and the miry clay, and sets our feet upon a rock.","emotion":"depressed","book":"Psalms","chapter":40,"verseStart":1,"verseEnd":2},{"id":"depressed-1-kings-19-7-8","reference":"1 Kings 19:7-8","text":"And the angel of the Lord came again the second time, and touched him, and said, Arise and eat; because the journey is too great for thee. And he arose, and did eat and drink, and went in the strength of that meat forty days and forty nights unto Horeb the mount of God.","reflection":"When Elijah was so low he wanted to die, God did not scold him — He fed him and let him rest.","emotion":"depressed","book":"1 Kings","chapter":19,"verseStart":7,"verseEnd":8},{"id":"depressed-isaiah-40-31","reference":"Isaiah 40:31","text":"But they that wait upon the Lord shall renew their strength; they shall mount up with wings as eagles; they shall run, and not be weary; and they shall walk, and not faint.","reflection":"Those who wait on the Lord renew their strength; they will rise again, even when worn down.","emotion":"depressed","book":"Isaiah","chapter":40,"verseStart":31,"verseEnd":31},{"id":"depressed-lamentations-3-22-23","reference":"Lamentations 3:22-23","text":"It is of the Lord’s mercies that we are not consumed, because his compassions fail not. They are new every morning: great is thy faithfulness.","reflection":"His mercies are new every morning — today has a fresh supply you have not used up.","emotion":"depressed","book":"Lamentations","chapter":3,"verseStart":22,"verseEnd":23},{"id":"depressed-matthew-11-28","reference":"Matthew 11:28","text":"Come unto me, all ye that labour and are heavy laden, and I will give you rest.","reflection":"Jesus invites the weary and heavy-laden to come to Him for rest. That includes you, today.","emotion":"depressed","book":"Matthew","chapter":11,"verseStart":28,"verseEnd":28},{"id":"depressed-psalm-3-3","reference":"Psalm 3:3","text":"But thou, O Lord, art a shield for me; my glory, and the lifter up of mine head.","reflection":"The Lord is a shield around you and the One who lifts up your head when you cannot lift it yourself.","emotion":"depressed","book":"Psalms","chapter":3,"verseStart":3,"verseEnd":3},{"id":"depressed-2-corinthians-4-8-9","reference":"2 Corinthians 4:8-9","text":"We are troubled on every side, yet not distressed; we are perplexed, but not in despair; Persecuted, but not forsaken; cast down, but not destroyed;","reflection":"Pressed but not crushed, struck down but not destroyed — this can be true of you too.","emotion":"depressed","book":"2 Corinthians","chapter":4,"verseStart":8,"verseEnd":9},{"id":"depressed-psalm-27-13-14","reference":"Psalm 27:13-14","text":"I had fainted, unless I had believed to see the goodness of the Lord in the land of the living. Wait on the Lord: be of good courage, and he shall strengthen thine heart: wait, I say, on the Lord.","reflection":"Wait on the Lord and take courage — you will see His goodness in the land of the living.","emotion":"depressed","book":"Psalms","chapter":27,"verseStart":13,"verseEnd":14},{"id":"depressed-john-16-33","reference":"John 16:33","text":"These things I have spoken unto you, that in me ye might have peace. In the world ye shall have tribulation: but be of good cheer; I have overcome the world.","reflection":"In the world you will have trouble, but take heart: Jesus has overcome the world.","emotion":"depressed","book":"John","chapter":16,"verseStart":33,"verseEnd":33},{"id":"depressed-psalm-143-7-8","reference":"Psalm 143:7-8","text":"Hear me speedily, O Lord: my spirit faileth: hide not thy face from me, lest I be like unto them that go down into the pit. Cause me to hear thy lovingkindness in the morning; for in thee do I trust: cause me to know the way wherein I should walk; for I lift up my soul unto thee.","reflection":"An honest prayer for the low days: \"Cause me to hear thy lovingkindness in the morning.\"","emotion":"depressed","book":"Psalms","chapter":143,"verseStart":7,"verseEnd":8},{"id":"depressed-psalm-147-3","reference":"Psalm 147:3","text":"He healeth the broken in heart, and bindeth up their wounds.","reflection":"He heals the brokenhearted and binds up their wounds — gently, and over time.","emotion":"depressed","book":"Psalms","chapter":147,"verseStart":3,"verseEnd":3}],"afraid":[{"id":"afraid-isaiah-41-10","reference":"Isaiah 41:10","text":"Fear thou not; for I am with thee: be not dismayed; for I am thy God: I will strengthen thee; yea, I will help thee; yea, I will uphold thee with the right hand of my righteousness.","reflection":"Five promises in one verse: I am with you, I am your God, I will strengthen, help, and uphold you.","emotion":"afraid","book":"Isaiah","chapter":41,"verseStart":10,"verseEnd":10},{"id":"afraid-psalm-27-1","reference":"Psalm 27:1","text":"The Lord is my light and my salvation; whom shall I fear? the Lord is the strength of my life; of whom shall I be afraid?","reflection":"When God is your light and your strength, fear loses its grip — whom shall you fear?","emotion":"afraid","book":"Psalms","chapter":27,"verseStart":1,"verseEnd":1},{"id":"afraid-2-timothy-1-7","reference":"2 Timothy 1:7","text":"For God hath not given us the spirit of fear; but of power, and of love, and of a sound mind.","reflection":"Fear is not from God. He has given you power, love, and a sound mind instead.","emotion":"afraid","book":"2 Timothy","chapter":1,"verseStart":7,"verseEnd":7},{"id":"afraid-psalm-56-3","reference":"Psalm 56:3","text":"What time I am afraid, I will trust in thee.","reflection":"One of the most honest prayers: \"What time I am afraid, I will trust in thee.\"","emotion":"afraid","book":"Psalms","chapter":56,"verseStart":3,"verseEnd":3},{"id":"afraid-1-john-4-18","reference":"1 John 4:18","text":"There is no fear in love; but perfect love casteth out fear: because fear hath torment. He that feareth is not made perfect in love.","reflection":"God’s perfect love casts out fear. When you receive it fully, fear has no room to live.","emotion":"afraid","book":"1 John","chapter":4,"verseStart":18,"verseEnd":18},{"id":"afraid-joshua-1-9","reference":"Joshua 1:9","text":"Have not I commanded thee? Be strong and of a good courage; be not afraid, neither be thou dismayed: for the Lord thy God is with thee whithersoever thou goest.","reflection":"Be strong and of good courage; do not be afraid, for the Lord is with you wherever you go.","emotion":"afraid","book":"Joshua","chapter":1,"verseStart":9,"verseEnd":9},{"id":"afraid-psalm-23-4","reference":"Psalm 23:4","text":"Yea, though I walk through the valley of the shadow of death, I will fear no evil: for thou art with me; thy rod and thy staff they comfort me.","reflection":"Even in the darkest valley you need fear no evil, for the Shepherd is with you.","emotion":"afraid","book":"Psalms","chapter":23,"verseStart":4,"verseEnd":4},{"id":"afraid-psalm-34-4","reference":"Psalm 34:4","text":"I sought the Lord, and he heard me, and delivered me from all my fears.","reflection":"David sought the Lord, and He delivered him from all his fears. Seek Him with your fear too.","emotion":"afraid","book":"Psalms","chapter":34,"verseStart":4,"verseEnd":4},{"id":"afraid-isaiah-43-1-2","reference":"Isaiah 43:1-2","text":"But now thus saith the Lord that created thee, O Jacob, and he that formed thee, O Israel, Fear not: for I have redeemed thee, I have called thee by thy name; thou art mine. When thou passest through the waters, I will be with thee; and through the rivers, they shall not overflow thee: when thou walkest through the fire, thou shalt not be burned; neither shall the flame kindle upon thee.","reflection":"When you pass through the waters and the fire, God says: I am with you, you are mine.","emotion":"afraid","book":"Isaiah","chapter":43,"verseStart":1,"verseEnd":2},{"id":"afraid-psalm-91-1-2","reference":"Psalm 91:1-2","text":"He that dwelleth in the secret place of the most High shall abide under the shadow of the Almighty. I will say of the Lord, He is my refuge and my fortress: my God; in him will I trust.","reflection":"Those who dwell in the shelter of the Most High rest in the shadow of the Almighty.","emotion":"afraid","book":"Psalms","chapter":91,"verseStart":1,"verseEnd":2},{"id":"afraid-proverbs-3-25-26","reference":"Proverbs 3:25-26","text":"Be not afraid of sudden fear, neither of the desolation of the wicked, when it cometh. For the Lord shall be thy confidence, and shall keep thy foot from being taken.","reflection":"You need not be afraid of sudden trouble, for the Lord will be your confidence.","emotion":"afraid","book":"Proverbs","chapter":3,"verseStart":25,"verseEnd":26},{"id":"afraid-psalm-118-6","reference":"Psalm 118:6","text":"The Lord is on my side; I will not fear: what can man do unto me?","reflection":"The Lord is on your side; you do not need to fear what people can do to you.","emotion":"afraid","book":"Psalms","chapter":118,"verseStart":6,"verseEnd":6},{"id":"afraid-isaiah-41-13","reference":"Isaiah 41:13","text":"For I the Lord thy God will hold thy right hand, saying unto thee, Fear not; I will help thee.","reflection":"God holds your right hand and says to you, \"Fear not; I will help you.\"","emotion":"afraid","book":"Isaiah","chapter":41,"verseStart":13,"verseEnd":13}],"anxious":[{"id":"anxious-philippians-4-6-7","reference":"Philippians 4:6-7","text":"Be careful for nothing; but in every thing by prayer and supplication with thanksgiving let your requests be made known unto God. And the peace of God, which passeth all understanding, shall keep your hearts and minds through Christ Jesus.","reflection":"Be anxious for nothing; bring it all to God in prayer, and His peace will guard your heart.","emotion":"anxious","book":"Philippians","chapter":4,"verseStart":6,"verseEnd":7},{"id":"anxious-1-peter-5-7","reference":"1 Peter 5:7","text":"Casting all your care upon him; for he careth for you.","reflection":"God is not burdened by your worries — He cares for you. Cast all of it on Him.","emotion":"anxious","book":"1 Peter","chapter":5,"verseStart":7,"verseEnd":7},{"id":"anxious-matthew-6-25-26","reference":"Matthew 6:25-26","text":"Therefore I say unto you, Take no thought for your life, what ye shall eat, or what ye shall drink; nor yet for your body, what ye shall put on. Is not the life more than meat, and the body than raiment? Behold the fowls of the air: for they sow not, neither do they reap, nor gather into barns; yet your heavenly Father feedeth them. Are ye not much better than they?","reflection":"If God feeds the birds, He will care for you. You are far more valuable to Him.","emotion":"anxious","book":"Matthew","chapter":6,"verseStart":25,"verseEnd":26},{"id":"anxious-matthew-6-34","reference":"Matthew 6:34","text":"Take therefore no thought for the morrow: for the morrow shall take thought for the things of itself. Sufficient unto the day is the evil thereof.","reflection":"Do not carry tomorrow’s weight today. Each day has enough — stay with what is in front of you.","emotion":"anxious","book":"Matthew","chapter":6,"verseStart":34,"verseEnd":34},{"id":"anxious-psalm-55-22","reference":"Psalm 55:22","text":"Cast thy burden upon the Lord, and he shall sustain thee: he shall never suffer the righteous to be moved.","reflection":"Cast your burden on the Lord, and He will sustain you. He will not let you be shaken.","emotion":"anxious","book":"Psalms","chapter":55,"verseStart":22,"verseEnd":22},{"id":"anxious-john-14-27","reference":"John 14:27","text":"Peace I leave with you, my peace I give unto you: not as the world giveth, give I unto you. Let not your heart be troubled, neither let it be afraid.","reflection":"Jesus gives a peace the world cannot — let it quiet your troubled, anxious heart.","emotion":"anxious","book":"John","chapter":14,"verseStart":27,"verseEnd":27},{"id":"anxious-isaiah-26-3","reference":"Isaiah 26:3","text":"Thou wilt keep him in perfect peace, whose mind is stayed on thee: because he trusteth in thee.","reflection":"God keeps in perfect peace the mind that is fixed on Him. Where your mind rests matters.","emotion":"anxious","book":"Isaiah","chapter":26,"verseStart":3,"verseEnd":3},{"id":"anxious-psalm-94-19","reference":"Psalm 94:19","text":"In the multitude of my thoughts within me thy comforts delight my soul.","reflection":"When anxious thoughts multiply within you, God’s comfort delights your soul.","emotion":"anxious","book":"Psalms","chapter":94,"verseStart":19,"verseEnd":19},{"id":"anxious-matthew-11-28-29","reference":"Matthew 11:28-29","text":"Come unto me, all ye that labour and are heavy laden, and I will give you rest. Take my yoke upon you, and learn of me; for I am meek and lowly in heart: and ye shall find rest unto your souls.","reflection":"Come to Jesus, take His gentle yoke, and you will find rest for your weary, racing mind.","emotion":"anxious","book":"Matthew","chapter":11,"verseStart":28,"verseEnd":29},{"id":"anxious-proverbs-12-25","reference":"Proverbs 12:25","text":"Heaviness in the heart of man maketh it stoop: but a good word maketh it glad.","reflection":"Anxiety weighs the heart down, but a good word makes it glad. Let Scripture be that word.","emotion":"anxious","book":"Proverbs","chapter":12,"verseStart":25,"verseEnd":25},{"id":"anxious-psalm-46-1-2","reference":"Psalm 46:1-2","text":"God is our refuge and strength, a very present help in trouble. Therefore will not we fear, though the earth be removed, and though the mountains be carried into the midst of the sea;","reflection":"God is your refuge and strength; you need not fear even when everything feels shaky.","emotion":"anxious","book":"Psalms","chapter":46,"verseStart":1,"verseEnd":2},{"id":"anxious-colossians-3-15","reference":"Colossians 3:15","text":"And let the peace of God rule in your hearts, to the which also ye are called in one body; and be ye thankful.","reflection":"Let the peace of God rule — act as the umpire — in your heart.","emotion":"anxious","book":"Colossians","chapter":3,"verseStart":15,"verseEnd":15}],"overwhelmed":[{"id":"overwhelmed-psalm-61-2","reference":"Psalm 61:2","text":"From the end of the earth will I cry unto thee, when my heart is overwhelmed: lead me to the rock that is higher than I.","reflection":"David did not pretend to be strong. When overwhelmed, he cried out for a higher rock — so can you.","emotion":"overwhelmed","book":"Psalms","chapter":61,"verseStart":2,"verseEnd":2},{"id":"overwhelmed-2-corinthians-12-9","reference":"2 Corinthians 12:9","text":"And he said unto me, My grace is sufficient for thee: for my strength is made perfect in weakness. Most gladly therefore will I rather glory in my infirmities, that the power of Christ may rest upon me.","reflection":"God’s grace is sufficient; His strength is made perfect in your weakness, not your strength.","emotion":"overwhelmed","book":"2 Corinthians","chapter":12,"verseStart":9,"verseEnd":9},{"id":"overwhelmed-philippians-4-13","reference":"Philippians 4:13","text":"I can do all things through Christ which strengtheneth me.","reflection":"Whatever God calls you to face, He gives the strength for it through Christ.","emotion":"overwhelmed","book":"Philippians","chapter":4,"verseStart":13,"verseEnd":13},{"id":"overwhelmed-psalm-46-1","reference":"Psalm 46:1","text":"God is our refuge and strength, a very present help in trouble.","reflection":"God is a very present help in trouble — a refuge you can run to right now.","emotion":"overwhelmed","book":"Psalms","chapter":46,"verseStart":1,"verseEnd":1},{"id":"overwhelmed-matthew-11-28","reference":"Matthew 11:28","text":"Come unto me, all ye that labour and are heavy laden, and I will give you rest.","reflection":"Come to Jesus, all who labour and are heavy laden, and He will give you rest.","emotion":"overwhelmed","book":"Matthew","chapter":11,"verseStart":28,"verseEnd":28},{"id":"overwhelmed-matthew-6-34","reference":"Matthew 6:34","text":"Take therefore no thought for the morrow: for the morrow shall take thought for the things of itself. Sufficient unto the day is the evil thereof.","reflection":"Do not carry tomorrow’s burden today; sufficient for the day is its own trouble.","emotion":"overwhelmed","book":"Matthew","chapter":6,"verseStart":34,"verseEnd":34},{"id":"overwhelmed-isaiah-43-2","reference":"Isaiah 43:2","text":"When thou passest through the waters, I will be with thee; and through the rivers, they shall not overflow thee: when thou walkest through the fire, thou shalt not be burned; neither shall the flame kindle upon thee.","reflection":"When you pass through deep waters, they will not overflow you — God is with you in them.","emotion":"overwhelmed","book":"Isaiah","chapter":43,"verseStart":2,"verseEnd":2},{"id":"overwhelmed-psalm-142-3","reference":"Psalm 142:3","text":"When my spirit was overwhelmed within me, then thou knewest my path. In the way wherein I walked have they privily laid a snare for me.","reflection":"Even when your spirit is overwhelmed within you, God knows your path. You are not lost to Him.","emotion":"overwhelmed","book":"Psalms","chapter":142,"verseStart":3,"verseEnd":3},{"id":"overwhelmed-psalm-121-1-2","reference":"Psalm 121:1-2","text":"I will lift up mine eyes unto the hills, from whence cometh my help. My help cometh from the Lord, which made heaven and earth.","reflection":"Lift your eyes up; your help comes from the Lord, the Maker of heaven and earth.","emotion":"overwhelmed","book":"Psalms","chapter":121,"verseStart":1,"verseEnd":2},{"id":"overwhelmed-isaiah-40-29","reference":"Isaiah 40:29","text":"He giveth power to the faint; and to them that have no might he increaseth strength.","reflection":"He gives power to the faint, and to those with no might He increases strength.","emotion":"overwhelmed","book":"Isaiah","chapter":40,"verseStart":29,"verseEnd":29},{"id":"overwhelmed-deuteronomy-33-27","reference":"Deuteronomy 33:27","text":"The eternal God is thy refuge, and underneath are the everlasting arms: and he shall thrust out the enemy from before thee; and shall say, Destroy them.","reflection":"The eternal God is your refuge, and underneath are the everlasting arms.","emotion":"overwhelmed","book":"Deuteronomy","chapter":33,"verseStart":27,"verseEnd":27},{"id":"overwhelmed-psalm-55-22","reference":"Psalm 55:22","text":"Cast thy burden upon the Lord, and he shall sustain thee: he shall never suffer the righteous to be moved.","reflection":"Cast your burden on the Lord; He will sustain you and never let the righteous be moved.","emotion":"overwhelmed","book":"Psalms","chapter":55,"verseStart":22,"verseEnd":22}],"angry":[{"id":"angry-ephesians-4-26","reference":"Ephesians 4:26","text":"Be ye angry, and sin not: let not the sun go down upon your wrath:","reflection":"Anger itself is not sin — but bring it to God before the day ends; do not let it fester.","emotion":"angry","book":"Ephesians","chapter":4,"verseStart":26,"verseEnd":26},{"id":"angry-proverbs-15-1","reference":"Proverbs 15:1","text":"A soft answer turneth away wrath: but grievous words stir up anger.","reflection":"A soft answer turns away wrath. Gentleness can defuse what harsh words would ignite.","emotion":"angry","book":"Proverbs","chapter":15,"verseStart":1,"verseEnd":1},{"id":"angry-psalm-37-8","reference":"Psalm 37:8","text":"Cease from anger, and forsake wrath: fret not thyself in any wise to do evil.","reflection":"Holding onto anger mostly hurts you. Let it go, and let God handle what is unjust.","emotion":"angry","book":"Psalms","chapter":37,"verseStart":8,"verseEnd":8},{"id":"angry-romans-12-19","reference":"Romans 12:19","text":"Dearly beloved, avenge not yourselves, but rather give place unto wrath: for it is written, Vengeance is mine; I will repay, saith the Lord.","reflection":"When deeply wronged, release the need to repay. God says, \"Vengeance is mine; I will repay.\"","emotion":"angry","book":"Romans","chapter":12,"verseStart":19,"verseEnd":19},{"id":"angry-proverbs-16-32","reference":"Proverbs 16:32","text":"He that is slow to anger is better than the mighty; and he that ruleth his spirit than he that taketh a city.","reflection":"Mastering your anger is a greater victory than taking a city. Self-control is strength.","emotion":"angry","book":"Proverbs","chapter":16,"verseStart":32,"verseEnd":32},{"id":"angry-james-1-19-20","reference":"James 1:19-20","text":"Wherefore, my beloved brethren, let every man be swift to hear, slow to speak, slow to wrath: For the wrath of man worketh not the righteousness of God.","reflection":"Be quick to hear, slow to speak, slow to anger; human anger does not produce God’s righteousness.","emotion":"angry","book":"James","chapter":1,"verseStart":19,"verseEnd":20},{"id":"angry-ecclesiastes-7-9","reference":"Ecclesiastes 7:9","text":"Be not hasty in thy spirit to be angry: for anger resteth in the bosom of fools.","reflection":"Do not be quick in spirit to be angry, for anger rests in the heart of fools.","emotion":"angry","book":"Ecclesiastes","chapter":7,"verseStart":9,"verseEnd":9},{"id":"angry-proverbs-14-29","reference":"Proverbs 14:29","text":"He that is slow to wrath is of great understanding: but he that is hasty of spirit exalteth folly.","reflection":"The patient have great understanding, but the quick-tempered display their folly.","emotion":"angry","book":"Proverbs","chapter":14,"verseStart":29,"verseEnd":29},{"id":"angry-colossians-3-8","reference":"Colossians 3:8","text":"But now ye also put off all these; anger, wrath, malice, blasphemy, filthy communication out of your mouth.","reflection":"Put away anger, wrath, and malice — lay them down like a heavy coat you no longer need.","emotion":"angry","book":"Colossians","chapter":3,"verseStart":8,"verseEnd":8},{"id":"angry-proverbs-19-11","reference":"Proverbs 19:11","text":"The discretion of a man deferreth his anger; and it is his glory to pass over a transgression.","reflection":"Good sense makes one slow to anger, and it is to your glory to overlook an offense.","emotion":"angry","book":"Proverbs","chapter":19,"verseStart":11,"verseEnd":11},{"id":"angry-ephesians-4-31-32","reference":"Ephesians 4:31-32","text":"Let all bitterness, and wrath, and anger, and clamour, and evil speaking, be put away from you, with all malice: And be ye kind one to another, tenderhearted, forgiving one another, even as God for Christ’s sake hath forgiven you.","reflection":"Put away bitterness, and instead be kind and forgiving, as God in Christ forgave you.","emotion":"angry","book":"Ephesians","chapter":4,"verseStart":31,"verseEnd":32},{"id":"angry-psalm-4-4","reference":"Psalm 4:4","text":"Stand in awe, and sin not: commune with your own heart upon your bed, and be still. Selah.","reflection":"Be angry, and do not sin; ponder it on your bed, and be still before God.","emotion":"angry","book":"Psalms","chapter":4,"verseStart":4,"verseEnd":4}],"guilty":[{"id":"guilty-1-john-1-9","reference":"1 John 1:9","text":"If we confess our sins, he is faithful and just to forgive us our sins, and to cleanse us from all unrighteousness.","reflection":"Bring your sin to God honestly, and He is faithful and just to forgive and cleanse you completely.","emotion":"guilty","book":"1 John","chapter":1,"verseStart":9,"verseEnd":9},{"id":"guilty-romans-8-1","reference":"Romans 8:1","text":"There is therefore now no condemnation to them which are in Christ Jesus, who walk not after the flesh, but after the Spirit.","reflection":"If you are in Christ, the verdict is already in: there is now no condemnation. None.","emotion":"guilty","book":"Romans","chapter":8,"verseStart":1,"verseEnd":1},{"id":"guilty-psalm-103-12","reference":"Psalm 103:12","text":"As far as the east is from the west, so far hath he removed our transgressions from us.","reflection":"As far as the east is from the west — that is how completely God removes your sin from you.","emotion":"guilty","book":"Psalms","chapter":103,"verseStart":12,"verseEnd":12},{"id":"guilty-isaiah-1-18","reference":"Isaiah 1:18","text":"Come now, and let us reason together, saith the Lord: though your sins be as scarlet, they shall be as white as snow; though they be red like crimson, they shall be as wool.","reflection":"God invites you to reason together; though your sins be as scarlet, they shall be white as snow.","emotion":"guilty","book":"Isaiah","chapter":1,"verseStart":18,"verseEnd":18},{"id":"guilty-romans-3-23-24","reference":"Romans 3:23-24","text":"For all have sinned, and come short of the glory of God; Being justified freely by his grace through the redemption that is in Christ Jesus:","reflection":"All have fallen short — and all can be justified freely by His grace through Christ.","emotion":"guilty","book":"Romans","chapter":3,"verseStart":23,"verseEnd":24},{"id":"guilty-psalm-32-5","reference":"Psalm 32:5","text":"I acknowledged my sin unto thee, and mine iniquity have I not hid. I said, I will confess my transgressions unto the Lord; and thou forgavest the iniquity of my sin. Selah.","reflection":"When David confessed and stopped hiding, God forgave the guilt of his sin. So He will for you.","emotion":"guilty","book":"Psalms","chapter":32,"verseStart":5,"verseEnd":5},{"id":"guilty-psalm-51-10","reference":"Psalm 51:10","text":"Create in me a clean heart, O God; and renew a right spirit within me.","reflection":"You can pray David’s prayer: \"Create in me a clean heart, O God; renew a right spirit within me.\"","emotion":"guilty","book":"Psalms","chapter":51,"verseStart":10,"verseEnd":10},{"id":"guilty-hebrews-8-12","reference":"Hebrews 8:12","text":"For I will be merciful to their unrighteousness, and their sins and their iniquities will I remember no more.","reflection":"God says He will be merciful to your wrongs and remember your sins no more.","emotion":"guilty","book":"Hebrews","chapter":8,"verseStart":12,"verseEnd":12},{"id":"guilty-micah-7-19","reference":"Micah 7:19","text":"He will turn again, he will have compassion upon us; he will subdue our iniquities; and thou wilt cast all their sins into the depths of the sea.","reflection":"He will cast all your sins into the depths of the sea — not the shallows where they wash back.","emotion":"guilty","book":"Micah","chapter":7,"verseStart":19,"verseEnd":19},{"id":"guilty-2-corinthians-5-17","reference":"2 Corinthians 5:17","text":"Therefore if any man be in Christ, he is a new creature: old things are passed away; behold, all things are become new.","reflection":"In Christ you are a new creation; the old has passed away, and the new has come.","emotion":"guilty","book":"2 Corinthians","chapter":5,"verseStart":17,"verseEnd":17},{"id":"guilty-isaiah-43-25","reference":"Isaiah 43:25","text":"I, even I, am he that blotteth out thy transgressions for mine own sake, and will not remember thy sins.","reflection":"God blots out your transgressions for His own sake, and remembers your sins no more.","emotion":"guilty","book":"Isaiah","chapter":43,"verseStart":25,"verseEnd":25},{"id":"guilty-1-john-2-1","reference":"1 John 2:1","text":"My little children, these things write I unto you, that ye sin not. And if any man sin, we have an advocate with the Father, Jesus Christ the righteous:","reflection":"If you do sin, you have an Advocate with the Father, Jesus Christ the righteous.","emotion":"guilty","book":"1 John","chapter":2,"verseStart":1,"verseEnd":1}],"tempted":[{"id":"tempted-1-corinthians-10-13","reference":"1 Corinthians 10:13","text":"There hath no temptation taken you but such as is common to man: but God is faithful, who will not suffer you to be tempted above that ye are able; but will with the temptation also make a way to escape, that ye may be able to bear it.","reflection":"No temptation is beyond what you can bear — God always provides a way of escape.","emotion":"tempted","book":"1 Corinthians","chapter":10,"verseStart":13,"verseEnd":13},{"id":"tempted-james-1-12","reference":"James 1:12","text":"Blessed is the man that endureth temptation: for when he is tried, he shall receive the crown of life, which the Lord hath promised to them that love him.","reflection":"Blessed is the one who endures temptation; having stood the test, they receive the crown of life.","emotion":"tempted","book":"James","chapter":1,"verseStart":12,"verseEnd":12},{"id":"tempted-hebrews-2-18","reference":"Hebrews 2:18","text":"For in that he himself hath suffered being tempted, he is able to succour them that are tempted.","reflection":"Because Jesus Himself was tempted, He is able to help you when you are being tempted.","emotion":"tempted","book":"Hebrews","chapter":2,"verseStart":18,"verseEnd":18},{"id":"tempted-hebrews-4-15-16","reference":"Hebrews 4:15-16","text":"For we have not an high priest which cannot be touched with the feeling of our infirmities; but was in all points tempted like as we are, yet without sin. Let us therefore come boldly unto the throne of grace, that we may obtain mercy, and find grace to help in time of need.","reflection":"Your High Priest understands temptation; come boldly to His throne to find grace to help.","emotion":"tempted","book":"Hebrews","chapter":4,"verseStart":15,"verseEnd":16},{"id":"tempted-james-4-7","reference":"James 4:7","text":"Submit yourselves therefore to God. Resist the devil, and he will flee from you.","reflection":"Submit to God, resist the devil, and he will flee from you. You are not powerless.","emotion":"tempted","book":"James","chapter":4,"verseStart":7,"verseEnd":7},{"id":"tempted-matthew-26-41","reference":"Matthew 26:41","text":"Watch and pray, that ye enter not into temptation: the spirit indeed is willing, but the flesh is weak.","reflection":"Watch and pray, so you do not fall — the spirit is willing, but the flesh is weak.","emotion":"tempted","book":"Matthew","chapter":26,"verseStart":41,"verseEnd":41},{"id":"tempted-psalm-119-11","reference":"Psalm 119:11","text":"Thy word have I hid in mine heart, that I might not sin against thee.","reflection":"Hiding God’s word in your heart is a guard against sin in the moment of pressure.","emotion":"tempted","book":"Psalms","chapter":119,"verseStart":11,"verseEnd":11},{"id":"tempted-1-peter-5-8-9","reference":"1 Peter 5:8-9","text":"Be sober, be vigilant; because your adversary the devil, as a roaring lion, walketh about, seeking whom he may devour: Whom resist stedfast in the faith, knowing that the same afflictions are accomplished in your brethren that are in the world.","reflection":"Be sober and watchful; resist the enemy, firm in faith — you are not the only one in this fight.","emotion":"tempted","book":"1 Peter","chapter":5,"verseStart":8,"verseEnd":9},{"id":"tempted-galatians-5-16","reference":"Galatians 5:16","text":"This I say then, Walk in the Spirit, and ye shall not fulfil the lust of the flesh.","reflection":"Walk by the Spirit, and you will not gratify the desires of the flesh.","emotion":"tempted","book":"Galatians","chapter":5,"verseStart":16,"verseEnd":16},{"id":"tempted-2-peter-2-9","reference":"2 Peter 2:9","text":"The Lord knoweth how to deliver the godly out of temptations, and to reserve the unjust unto the day of judgment to be punished:","reflection":"The Lord knows how to deliver the godly out of temptation. He has not left you to manage alone.","emotion":"tempted","book":"2 Peter","chapter":2,"verseStart":9,"verseEnd":9},{"id":"tempted-romans-6-14","reference":"Romans 6:14","text":"For sin shall not have dominion over you: for ye are not under the law, but under grace.","reflection":"Sin shall not be your master, for you are not under law but under grace.","emotion":"tempted","book":"Romans","chapter":6,"verseStart":14,"verseEnd":14},{"id":"tempted-2-timothy-2-22","reference":"2 Timothy 2:22","text":"Flee also youthful lusts: but follow righteousness, faith, charity, peace, with them that call on the Lord out of a pure heart.","reflection":"Flee the desires of youth, and pursue righteousness, faith, love, and peace instead.","emotion":"tempted","book":"2 Timothy","chapter":2,"verseStart":22,"verseEnd":22}],"doubtful":[{"id":"doubtful-mark-9-24","reference":"Mark 9:24","text":"And straightway the father of the child cried out, and said with tears, Lord, I believe; help thou mine unbelief.","reflection":"The honest prayer of a struggling father: \"Lord, I believe; help thou mine unbelief.\" God hears it.","emotion":"doubtful","book":"Mark","chapter":9,"verseStart":24,"verseEnd":24},{"id":"doubtful-james-1-6","reference":"James 1:6","text":"But let him ask in faith, nothing wavering. For he that wavereth is like a wave of the sea driven with the wind and tossed.","reflection":"Ask in faith — but the very fact that you are asking shows your faith is not gone.","emotion":"doubtful","book":"James","chapter":1,"verseStart":6,"verseEnd":6},{"id":"doubtful-john-20-27-29","reference":"John 20:27-29","text":"Then saith he to Thomas, Reach hither thy finger, and behold my hands; and reach hither thy hand, and thrust it into my side: and be not faithless, but believing. And Thomas answered and said unto him, My Lord and my God. Jesus saith unto him, Thomas, because thou hast seen me, thou hast believed: blessed are they that have not seen, and yet have believed.","reflection":"Jesus met doubting Thomas with patience, not rebuke. He meets your honest doubt the same way.","emotion":"doubtful","book":"John","chapter":20,"verseStart":27,"verseEnd":29},{"id":"doubtful-hebrews-11-1","reference":"Hebrews 11:1","text":"Now faith is the substance of things hoped for, the evidence of things not seen.","reflection":"Faith is the substance of things hoped for, the evidence of things not seen — not the absence of questions.","emotion":"doubtful","book":"Hebrews","chapter":11,"verseStart":1,"verseEnd":1},{"id":"doubtful-isaiah-55-8-9","reference":"Isaiah 55:8-9","text":"For my thoughts are not your thoughts, neither are your ways my ways, saith the Lord. For as the heavens are higher than the earth, so are my ways higher than your ways, and my thoughts than your thoughts.","reflection":"God’s thoughts and ways are higher than yours; not understanding everything is to be expected.","emotion":"doubtful","book":"Isaiah","chapter":55,"verseStart":8,"verseEnd":9},{"id":"doubtful-proverbs-3-5-6","reference":"Proverbs 3:5-6","text":"Trust in the Lord with all thine heart; and lean not unto thine own understanding. In all thy ways acknowledge him, and he shall direct thy paths.","reflection":"Trust in the Lord with all your heart; lean not on your own understanding, and He will direct you.","emotion":"doubtful","book":"Proverbs","chapter":3,"verseStart":5,"verseEnd":6},{"id":"doubtful-jude-1-22","reference":"Jude 1:22","text":"And of some have compassion, making a difference:","reflection":"God’s people are told to be merciful to those who doubt — your doubt does not disqualify you.","emotion":"doubtful","book":"Jude","chapter":1,"verseStart":22,"verseEnd":22},{"id":"doubtful-romans-10-17","reference":"Romans 10:17","text":"So then faith cometh by hearing, and hearing by the word of God.","reflection":"Faith comes by hearing, and hearing by the word of God. Feed your faith on Scripture.","emotion":"doubtful","book":"Romans","chapter":10,"verseStart":17,"verseEnd":17},{"id":"doubtful-psalm-77-11-12","reference":"Psalm 77:11-12","text":"I will remember the works of the Lord: surely I will remember thy wonders of old. I will meditate also of all thy work, and talk of thy doings.","reflection":"When doubt rises, remember God’s past faithfulness; recall His works and meditate on them.","emotion":"doubtful","book":"Psalms","chapter":77,"verseStart":11,"verseEnd":12},{"id":"doubtful-habakkuk-3-17-18","reference":"Habakkuk 3:17-18","text":"Although the fig tree shall not blossom, neither shall fruit be in the vines; the labour of the olive shall fail, and the fields shall yield no meat; the flock shall be cut off from the fold, and there shall be no herd in the stalls: Yet I will rejoice in the Lord, I will joy in the God of my salvation.","reflection":"Even when nothing visibly works out, you can still choose to rejoice in the God of your salvation.","emotion":"doubtful","book":"Habakkuk","chapter":3,"verseStart":17,"verseEnd":18},{"id":"doubtful-mark-11-24","reference":"Mark 11:24","text":"Therefore I say unto you, What things soever ye desire, when ye pray, believe that ye receive them, and ye shall have them.","reflection":"Whatever you ask in prayer, believe that you receive it — faith grows as you practice it.","emotion":"doubtful","book":"Mark","chapter":11,"verseStart":24,"verseEnd":24}],"discouraged":[{"id":"discouraged-joshua-1-9","reference":"Joshua 1:9","text":"Have not I commanded thee? Be strong and of a good courage; be not afraid, neither be thou dismayed: for the Lord thy God is with thee whithersoever thou goest.","reflection":"Be strong and courageous; do not be discouraged, for the Lord your God is with you everywhere.","emotion":"discouraged","book":"Joshua","chapter":1,"verseStart":9,"verseEnd":9},{"id":"discouraged-isaiah-40-31","reference":"Isaiah 40:31","text":"But they that wait upon the Lord shall renew their strength; they shall mount up with wings as eagles; they shall run, and not be weary; and they shall walk, and not faint.","reflection":"Those who wait on the Lord renew their strength and rise up with wings like eagles.","emotion":"discouraged","book":"Isaiah","chapter":40,"verseStart":31,"verseEnd":31},{"id":"discouraged-galatians-6-9","reference":"Galatians 6:9","text":"And let us not be weary in well doing: for in due season we shall reap, if we faint not.","reflection":"Do not grow weary in doing good; in due season you will reap, if you do not give up.","emotion":"discouraged","book":"Galatians","chapter":6,"verseStart":9,"verseEnd":9},{"id":"discouraged-philippians-4-13","reference":"Philippians 4:13","text":"I can do all things through Christ which strengtheneth me.","reflection":"You can do all things through Christ who strengthens you — even this hard, draining thing.","emotion":"discouraged","book":"Philippians","chapter":4,"verseStart":13,"verseEnd":13},{"id":"discouraged-psalm-27-13-14","reference":"Psalm 27:13-14","text":"I had fainted, unless I had believed to see the goodness of the Lord in the land of the living. Wait on the Lord: be of good courage, and he shall strengthen thine heart: wait, I say, on the Lord.","reflection":"Take heart and wait on the Lord; you will yet see His goodness in the land of the living.","emotion":"discouraged","book":"Psalms","chapter":27,"verseStart":13,"verseEnd":14},{"id":"discouraged-deuteronomy-31-8","reference":"Deuteronomy 31:8","text":"And the Lord, he it is that doth go before thee; he will be with thee, he will not fail thee, neither forsake thee: fear not, neither be dismayed.","reflection":"The Lord goes before you and will be with you; do not fear or be dismayed.","emotion":"discouraged","book":"Deuteronomy","chapter":31,"verseStart":8,"verseEnd":8},{"id":"discouraged-2-corinthians-4-16-18","reference":"2 Corinthians 4:16-18","text":"For which cause we faint not; but though our outward man perish, yet the inward man is renewed day by day. For our light affliction, which is but for a moment, worketh for us a far more exceeding and eternal weight of glory; While we look not at the things which are seen, but at the things which are not seen: for the things which are seen are temporal; but the things which are not seen are eternal.","reflection":"Do not lose heart; though the outer self wastes away, the inner self is renewed day by day.","emotion":"discouraged","book":"2 Corinthians","chapter":4,"verseStart":16,"verseEnd":18},{"id":"discouraged-isaiah-41-10","reference":"Isaiah 41:10","text":"Fear thou not; for I am with thee: be not dismayed; for I am thy God: I will strengthen thee; yea, I will help thee; yea, I will uphold thee with the right hand of my righteousness.","reflection":"Fear not, for God is with you; He will strengthen and help you and hold you up.","emotion":"discouraged","book":"Isaiah","chapter":41,"verseStart":10,"verseEnd":10},{"id":"discouraged-1-corinthians-15-58","reference":"1 Corinthians 15:58","text":"Therefore, my beloved brethren, be ye stedfast, unmoveable, always abounding in the work of the Lord, forasmuch as ye know that your labour is not in vain in the Lord.","reflection":"Be steadfast; your labour in the Lord is not in vain, even when it feels fruitless.","emotion":"discouraged","book":"1 Corinthians","chapter":15,"verseStart":58,"verseEnd":58},{"id":"discouraged-nehemiah-8-10","reference":"Nehemiah 8:10","text":"Then he said unto them, Go your way, eat the fat, and drink the sweet, and send portions unto them for whom nothing is prepared: for this day is holy unto our Lord: neither be ye sorry; for the joy of the Lord is your strength.","reflection":"The joy of the Lord is your strength — a source of power that does not depend on results.","emotion":"discouraged","book":"Nehemiah","chapter":8,"verseStart":10,"verseEnd":10},{"id":"discouraged-psalm-31-24","reference":"Psalm 31:24","text":"Be of good courage, and he shall strengthen your heart, all ye that hope in the Lord.","reflection":"Be of good courage, and He will strengthen your heart, all you who hope in the Lord.","emotion":"discouraged","book":"Psalms","chapter":31,"verseStart":24,"verseEnd":24},{"id":"discouraged-hebrews-12-1-2","reference":"Hebrews 12:1-2","text":"Wherefore seeing we also are compassed about with so great a cloud of witnesses, let us lay aside every weight, and the sin which doth so easily beset us, and let us run with patience the race that is set before us, Looking unto Jesus the author and finisher of our faith; who for the joy that was set before him endured the cross, despising the shame, and is set down at the right hand of the throne of God.","reflection":"Run your race with endurance, looking to Jesus, the author and finisher of your faith.","emotion":"discouraged","book":"Hebrews","chapter":12,"verseStart":1,"verseEnd":2}],"insecure":[{"id":"insecure-psalm-139-14","reference":"Psalm 139:14","text":"I will praise thee; for I am fearfully and wonderfully made: marvellous are thy works; and that my soul knoweth right well.","reflection":"You are fearfully and wonderfully made. Your worth was settled by your Maker, not your critics.","emotion":"insecure","book":"Psalms","chapter":139,"verseStart":14,"verseEnd":14},{"id":"insecure-isaiah-43-1-4","reference":"Isaiah 43:1-4","text":"But now thus saith the Lord that created thee, O Jacob, and he that formed thee, O Israel, Fear not: for I have redeemed thee, I have called thee by thy name; thou art mine. When thou passest through the waters, I will be with thee; and through the rivers, they shall not overflow thee: when thou walkest through the fire, thou shalt not be burned; neither shall the flame kindle upon thee. For I am the Lord thy God, the Holy One of Israel, thy Saviour: I gave Egypt for thy ransom, Ethiopia and Seba for thee. Since thou wast precious in my sight, thou hast been honourable, and I have loved thee: therefore will I give men for thee, and people for thy life.","reflection":"God says you are precious in His eyes, honored, and loved. He calls you by name.","emotion":"insecure","book":"Isaiah","chapter":43,"verseStart":1,"verseEnd":4},{"id":"insecure-ephesians-2-10","reference":"Ephesians 2:10","text":"For we are his workmanship, created in Christ Jesus unto good works, which God hath before ordained that we should walk in them.","reflection":"You are God’s workmanship, created for good works He prepared beforehand for you to do.","emotion":"insecure","book":"Ephesians","chapter":2,"verseStart":10,"verseEnd":10},{"id":"insecure-jeremiah-1-5","reference":"Jeremiah 1:5","text":"Before I formed thee in the belly I knew thee; and before thou camest forth out of the womb I sanctified thee, and I ordained thee a prophet unto the nations.","reflection":"Before you were formed, God knew you. Your identity began in His mind, not in others’ opinions.","emotion":"insecure","book":"Jeremiah","chapter":1,"verseStart":5,"verseEnd":5},{"id":"insecure-1-peter-2-9","reference":"1 Peter 2:9","text":"But ye are a chosen generation, a royal priesthood, an holy nation, a peculiar people; that ye should shew forth the praises of him who hath called you out of darkness into his marvellous light:","reflection":"You are chosen, royal, holy, God’s own — called out of darkness into His marvelous light.","emotion":"insecure","book":"1 Peter","chapter":2,"verseStart":9,"verseEnd":9},{"id":"insecure-romans-8-31","reference":"Romans 8:31","text":"What shall we then say to these things? If God be for us, who can be against us?","reflection":"If God is for you, who can be against you? His verdict outweighs every other voice.","emotion":"insecure","book":"Romans","chapter":8,"verseStart":31,"verseEnd":31},{"id":"insecure-zephaniah-3-17","reference":"Zephaniah 3:17","text":"The Lord thy God in the midst of thee is mighty; he will save, he will rejoice over thee with joy; he will rest in his love, he will joy over thee with singing.","reflection":"God rejoices over you with gladness and quiets you with His love. He delights in you.","emotion":"insecure","book":"Zephaniah","chapter":3,"verseStart":17,"verseEnd":17},{"id":"insecure-galatians-2-20","reference":"Galatians 2:20","text":"I am crucified with Christ: nevertheless I live; yet not I, but Christ liveth in me: and the life which I now live in the flesh I live by the faith of the Son of God, who loved me, and gave himself for me.","reflection":"Your life is now Christ living in you — you are defined by Him, not by your failures.","emotion":"insecure","book":"Galatians","chapter":2,"verseStart":20,"verseEnd":20},{"id":"insecure-2-corinthians-12-9","reference":"2 Corinthians 12:9","text":"And he said unto me, My grace is sufficient for thee: for my strength is made perfect in weakness. Most gladly therefore will I rather glory in my infirmities, that the power of Christ may rest upon me.","reflection":"His grace is enough for you; His power is perfected in your weakness, not your perfection.","emotion":"insecure","book":"2 Corinthians","chapter":12,"verseStart":9,"verseEnd":9},{"id":"insecure-matthew-10-29-31","reference":"Matthew 10:29-31","text":"Are not two sparrows sold for a farthing? and one of them shall not fall on the ground without your Father. But the very hairs of your head are all numbered. Fear ye not therefore, ye are of more value than many sparrows.","reflection":"God knows the number of hairs on your head. You are worth more than many sparrows to Him.","emotion":"insecure","book":"Matthew","chapter":10,"verseStart":29,"verseEnd":31},{"id":"insecure-colossians-2-10","reference":"Colossians 2:10","text":"And ye are complete in him, which is the head of all principality and power:","reflection":"In Christ you are complete — not lacking, not less-than, but filled with His fullness.","emotion":"insecure","book":"Colossians","chapter":2,"verseStart":10,"verseEnd":10},{"id":"insecure-genesis-1-27","reference":"Genesis 1:27","text":"So God created man in his own image, in the image of God created he him; male and female created he them.","reflection":"You bear the image of God Himself. That is the dignity stamped on you from the beginning.","emotion":"insecure","book":"Genesis","chapter":1,"verseStart":27,"verseEnd":27}],"jealous":[{"id":"jealous-psalm-37-1-4","reference":"Psalm 37:1-4","text":"Fret not thyself because of evildoers, neither be thou envious against the workers of iniquity. For they shall soon be cut down like the grass, and wither as the green herb. Trust in the Lord, and do good; so shalt thou dwell in the land, and verily thou shalt be fed. Delight thyself also in the Lord; and he shall give thee the desires of thine heart.","reflection":"Do not fret over those who prosper; delight in the Lord, and He gives you the desires of your heart.","emotion":"jealous","book":"Psalms","chapter":37,"verseStart":1,"verseEnd":4},{"id":"jealous-proverbs-14-30","reference":"Proverbs 14:30","text":"A sound heart is the life of the flesh: but envy the rottenness of the bones.","reflection":"A peaceful heart gives life to the body, but envy rots the bones. Envy costs you, not them.","emotion":"jealous","book":"Proverbs","chapter":14,"verseStart":30,"verseEnd":30},{"id":"jealous-galatians-5-26","reference":"Galatians 5:26","text":"Let us not be desirous of vain glory, provoking one another, envying one another.","reflection":"Do not become conceited, provoking and envying one another — comparison only breeds strife.","emotion":"jealous","book":"Galatians","chapter":5,"verseStart":26,"verseEnd":26},{"id":"jealous-james-3-16","reference":"James 3:16","text":"For where envying and strife is, there is confusion and every evil work.","reflection":"Where there is envy and selfish ambition, there is disorder. Peace grows in the opposite soil.","emotion":"jealous","book":"James","chapter":3,"verseStart":16,"verseEnd":16},{"id":"jealous-philippians-4-11-12","reference":"Philippians 4:11-12","text":"Not that I speak in respect of want: for I have learned, in whatsoever state I am, therewith to be content. I know both how to be abased, and I know how to abound: every where and in all things I am instructed both to be full and to be hungry, both to abound and to suffer need.","reflection":"Paul learned contentment in any situation — it is a skill that can be learned, not a feeling you wait for.","emotion":"jealous","book":"Philippians","chapter":4,"verseStart":11,"verseEnd":12},{"id":"jealous-1-timothy-6-6-7","reference":"1 Timothy 6:6-7","text":"But godliness with contentment is great gain. For we brought nothing into this world, and it is certain we can carry nothing out.","reflection":"Godliness with contentment is great gain; we brought nothing in and can take nothing out.","emotion":"jealous","book":"1 Timothy","chapter":6,"verseStart":6,"verseEnd":7},{"id":"jealous-hebrews-13-5","reference":"Hebrews 13:5","text":"Let your conversation be without covetousness; and be content with such things as ye have: for he hath said, I will never leave thee, nor forsake thee.","reflection":"Be content with what you have, for God has said He will never leave you.","emotion":"jealous","book":"Hebrews","chapter":13,"verseStart":5,"verseEnd":5},{"id":"jealous-exodus-20-17","reference":"Exodus 20:17","text":"Thou shalt not covet thy neighbour’s house, thou shalt not covet thy neighbour’s wife, nor his manservant, nor his maidservant, nor his ox, nor his ass, nor any thing that is thy neighbour’s.","reflection":"The command not to covet is also a kindness — it frees you from always wanting another’s life.","emotion":"jealous","book":"Exodus","chapter":20,"verseStart":17,"verseEnd":17},{"id":"jealous-1-corinthians-13-4","reference":"1 Corinthians 13:4","text":"Charity suffereth long, and is kind; charity envieth not; charity vaunteth not itself, is not puffed up,","reflection":"Love does not envy. As love grows in you, the grip of jealousy loosens.","emotion":"jealous","book":"1 Corinthians","chapter":13,"verseStart":4,"verseEnd":4},{"id":"jealous-proverbs-23-17","reference":"Proverbs 23:17","text":"Let not thine heart envy sinners: but be thou in the fear of the Lord all the day long.","reflection":"Do not let your heart envy sinners, but continue in the fear of the Lord all day long.","emotion":"jealous","book":"Proverbs","chapter":23,"verseStart":17,"verseEnd":17},{"id":"jealous-psalm-73-2-3","reference":"Psalm 73:2-3","text":"But as for me, my feet were almost gone; my steps had well nigh slipped. For I was envious at the foolish, when I saw the prosperity of the wicked.","reflection":"Even Asaph nearly stumbled with envy at the prosperous — you are not alone in this struggle.","emotion":"jealous","book":"Psalms","chapter":73,"verseStart":2,"verseEnd":3}],"confused":[{"id":"confused-proverbs-3-5-6","reference":"Proverbs 3:5-6","text":"Trust in the Lord with all thine heart; and lean not unto thine own understanding. In all thy ways acknowledge him, and he shall direct thy paths.","reflection":"When you cannot see the path, trust the One who can; acknowledge Him, and He will direct your steps.","emotion":"confused","book":"Proverbs","chapter":3,"verseStart":5,"verseEnd":6},{"id":"confused-james-1-5","reference":"James 1:5","text":"If any of you lack wisdom, let him ask of God, that giveth to all men liberally, and upbraideth not; and it shall be given him.","reflection":"If you lack wisdom, ask God, who gives generously to all without finding fault.","emotion":"confused","book":"James","chapter":1,"verseStart":5,"verseEnd":5},{"id":"confused-1-corinthians-14-33","reference":"1 Corinthians 14:33","text":"For God is not the author of confusion, but of peace, as in all churches of the saints.","reflection":"God is not the author of confusion but of peace. You can ask Him to bring clarity.","emotion":"confused","book":"1 Corinthians","chapter":14,"verseStart":33,"verseEnd":33},{"id":"confused-psalm-119-105","reference":"Psalm 119:105","text":"Thy word is a lamp unto my feet, and a light unto my path.","reflection":"God’s word is a lamp to your feet — it shows the next step, which is enough for now.","emotion":"confused","book":"Psalms","chapter":119,"verseStart":105,"verseEnd":105},{"id":"confused-psalm-32-8","reference":"Psalm 32:8","text":"I will instruct thee and teach thee in the way which thou shalt go: I will guide thee with mine eye.","reflection":"God promises to instruct you and teach you the way you should go, with His eye upon you.","emotion":"confused","book":"Psalms","chapter":32,"verseStart":8,"verseEnd":8},{"id":"confused-isaiah-30-21","reference":"Isaiah 30:21","text":"And thine ears shall hear a word behind thee, saying, This is the way, walk ye in it, when ye turn to the right hand, and when ye turn to the left.","reflection":"You will hear a voice behind you saying, \"This is the way; walk in it,\" when you turn aside.","emotion":"confused","book":"Isaiah","chapter":30,"verseStart":21,"verseEnd":21},{"id":"confused-jeremiah-33-3","reference":"Jeremiah 33:3","text":"Call unto me, and I will answer thee, and shew thee great and mighty things, which thou knowest not.","reflection":"Call to God, and He will answer and show you great and hidden things you do not know.","emotion":"confused","book":"Jeremiah","chapter":33,"verseStart":3,"verseEnd":3},{"id":"confused-isaiah-55-8-9","reference":"Isaiah 55:8-9","text":"For my thoughts are not your thoughts, neither are your ways my ways, saith the Lord. For as the heavens are higher than the earth, so are my ways higher than your ways, and my thoughts than your thoughts.","reflection":"God’s ways are higher than yours; you do not need to understand it all to follow Him.","emotion":"confused","book":"Isaiah","chapter":55,"verseStart":8,"verseEnd":9},{"id":"confused-psalm-37-23","reference":"Psalm 37:23","text":"The steps of a good man are ordered by the Lord: and he delighteth in his way.","reflection":"The steps of a good person are ordered by the Lord, even when the way feels unclear.","emotion":"confused","book":"Psalms","chapter":37,"verseStart":23,"verseEnd":23},{"id":"confused-romans-8-28","reference":"Romans 8:28","text":"And we know that all things work together for good to them that love God, to them who are the called according to his purpose.","reflection":"God works all things — even the confusing ones — together for good to those who love Him.","emotion":"confused","book":"Romans","chapter":8,"verseStart":28,"verseEnd":28},{"id":"confused-proverbs-16-9","reference":"Proverbs 16:9","text":"A man’s heart deviseth his way: but the Lord directeth his steps.","reflection":"A person plans their way, but the Lord directs their steps. You can trust His leading.","emotion":"confused","book":"Proverbs","chapter":16,"verseStart":9,"verseEnd":9}],"hurting":[{"id":"hurting-psalm-34-19","reference":"Psalm 34:19","text":"Many are the afflictions of the righteous: but the Lord delivereth him out of them all.","reflection":"Many are the afflictions of the righteous, but the Lord delivers them out of them all.","emotion":"hurting","book":"Psalms","chapter":34,"verseStart":19,"verseEnd":19},{"id":"hurting-psalm-147-3","reference":"Psalm 147:3","text":"He healeth the broken in heart, and bindeth up their wounds.","reflection":"He heals the brokenhearted and binds up their wounds — body and soul alike.","emotion":"hurting","book":"Psalms","chapter":147,"verseStart":3,"verseEnd":3},{"id":"hurting-isaiah-53-5","reference":"Isaiah 53:5","text":"But he was wounded for our transgressions, he was bruised for our iniquities: the chastisement of our peace was upon him; and with his stripes we are healed.","reflection":"By His wounds we are healed. Jesus bore your suffering so you would not bear it alone.","emotion":"hurting","book":"Isaiah","chapter":53,"verseStart":5,"verseEnd":5},{"id":"hurting-james-5-14-15","reference":"James 5:14-15","text":"Is any sick among you? let him call for the elders of the church; and let them pray over him, anointing him with oil in the name of the Lord: And the prayer of faith shall save the sick, and the Lord shall raise him up; and if he have committed sins, they shall be forgiven him.","reflection":"Call on others to pray over you; the prayer of faith does real work in real bodies.","emotion":"hurting","book":"James","chapter":5,"verseStart":14,"verseEnd":15},{"id":"hurting-jeremiah-17-14","reference":"Jeremiah 17:14","text":"Heal me, O Lord, and I shall be healed; save me, and I shall be saved: for thou art my praise.","reflection":"A simple, honest prayer: \"Heal me, O Lord, and I shall be healed; save me, and I shall be saved.\"","emotion":"hurting","book":"Jeremiah","chapter":17,"verseStart":14,"verseEnd":14},{"id":"hurting-psalm-103-2-3","reference":"Psalm 103:2-3","text":"Bless the Lord, O my soul, and forget not all his benefits: Who forgiveth all thine iniquities; who healeth all thy diseases;","reflection":"Bless the Lord, who forgives all your sin and heals all your diseases. Forget not His benefits.","emotion":"hurting","book":"Psalms","chapter":103,"verseStart":2,"verseEnd":3},{"id":"hurting-psalm-30-2","reference":"Psalm 30:2","text":"O Lord my God, I cried unto thee, and thou hast healed me.","reflection":"David cried to the Lord for help, and God healed him. Bring your pain to Him directly.","emotion":"hurting","book":"Psalms","chapter":30,"verseStart":2,"verseEnd":2},{"id":"hurting-matthew-11-28","reference":"Matthew 11:28","text":"Come unto me, all ye that labour and are heavy laden, and I will give you rest.","reflection":"Come to Jesus, all who are weary and burdened with pain, and He will give you rest.","emotion":"hurting","book":"Matthew","chapter":11,"verseStart":28,"verseEnd":28},{"id":"hurting-2-corinthians-12-9","reference":"2 Corinthians 12:9","text":"And he said unto me, My grace is sufficient for thee: for my strength is made perfect in weakness. Most gladly therefore will I rather glory in my infirmities, that the power of Christ may rest upon me.","reflection":"When healing tarries, His grace is still sufficient, and His strength meets your weakness.","emotion":"hurting","book":"2 Corinthians","chapter":12,"verseStart":9,"verseEnd":9},{"id":"hurting-psalm-41-3","reference":"Psalm 41:3","text":"The Lord will strengthen him upon the bed of languishing: thou wilt make all his bed in his sickness.","reflection":"The Lord sustains and strengthens those on a bed of illness. He has not forgotten you.","emotion":"hurting","book":"Psalms","chapter":41,"verseStart":3,"verseEnd":3},{"id":"hurting-1-peter-2-24","reference":"1 Peter 2:24","text":"Who his own self bare our sins in his own body on the tree, that we, being dead to sins, should live unto righteousness: by whose stripes ye were healed.","reflection":"He bore our sins in His body on the tree — by His stripes you were healed.","emotion":"hurting","book":"1 Peter","chapter":2,"verseStart":24,"verseEnd":24},{"id":"hurting-revelation-21-4","reference":"Revelation 21:4","text":"And God shall wipe away all tears from their eyes; and there shall be no more death, neither sorrow, nor crying, neither shall there be any more pain: for the former things are passed away.","reflection":"A day is coming with no more pain; the former things will all have passed away.","emotion":"hurting","book":"Revelation","chapter":21,"verseStart":4,"verseEnd":4}],"provision":[{"id":"provision-philippians-4-19","reference":"Philippians 4:19","text":"But my God shall supply all your need according to his riches in glory by Christ Jesus.","reflection":"God will supply all your needs according to His riches in glory by Christ Jesus.","emotion":"provision","book":"Philippians","chapter":4,"verseStart":19,"verseEnd":19},{"id":"provision-matthew-6-31-33","reference":"Matthew 6:31-33","text":"Therefore take no thought, saying, What shall we eat? or, What shall we drink? or, Wherewithal shall we be clothed? (For after all these things do the Gentiles seek:) for your heavenly Father knoweth that ye have need of all these things. But seek ye first the kingdom of God, and his righteousness; and all these things shall be added unto you.","reflection":"Do not be anxious about food or clothing; seek first His kingdom, and these will be added to you.","emotion":"provision","book":"Matthew","chapter":6,"verseStart":31,"verseEnd":33},{"id":"provision-psalm-23-1","reference":"Psalm 23:1","text":"The Lord is my shepherd; I shall not want.","reflection":"The Lord is your shepherd; with Him as your provider, you shall not be in want.","emotion":"provision","book":"Psalms","chapter":23,"verseStart":1,"verseEnd":1},{"id":"provision-matthew-6-26","reference":"Matthew 6:26","text":"Behold the fowls of the air: for they sow not, neither do they reap, nor gather into barns; yet your heavenly Father feedeth them. Are ye not much better than they?","reflection":"God feeds the birds, who do not store up barns. You are worth far more to Him than they.","emotion":"provision","book":"Matthew","chapter":6,"verseStart":26,"verseEnd":26},{"id":"provision-psalm-37-25","reference":"Psalm 37:25","text":"I have been young, and now am old; yet have I not seen the righteous forsaken, nor his seed begging bread.","reflection":"David testified he had never seen the righteous forsaken or their children begging bread.","emotion":"provision","book":"Psalms","chapter":37,"verseStart":25,"verseEnd":25},{"id":"provision-luke-12-24","reference":"Luke 12:24","text":"Consider the ravens: for they neither sow nor reap; which neither have storehouse nor barn; and God feedeth them: how much more are ye better than the fowls?","reflection":"Consider the ravens: God feeds them. How much more valuable are you than the birds!","emotion":"provision","book":"Luke","chapter":12,"verseStart":24,"verseEnd":24},{"id":"provision-proverbs-3-9-10","reference":"Proverbs 3:9-10","text":"Honour the Lord with thy substance, and with the firstfruits of all thine increase: So shall thy barns be filled with plenty, and thy presses shall burst out with new wine.","reflection":"Honor the Lord with what you have, and your needs will not be the end of the story.","emotion":"provision","book":"Proverbs","chapter":3,"verseStart":9,"verseEnd":10},{"id":"provision-malachi-3-10","reference":"Malachi 3:10","text":"Bring ye all the tithes into the storehouse, that there may be meat in mine house, and prove me now herewith, saith the Lord of hosts, if I will not open you the windows of heaven, and pour you out a blessing, that there shall not be room enough to receive it.","reflection":"God invites you to test His faithfulness in giving — to see if He will not pour out blessing.","emotion":"provision","book":"Malachi","chapter":3,"verseStart":10,"verseEnd":10},{"id":"provision-2-corinthians-9-8","reference":"2 Corinthians 9:8","text":"And God is able to make all grace abound toward you; that ye, always having all sufficiency in all things, may abound to every good work:","reflection":"God is able to make all grace abound to you, so that you have all you need for every good work.","emotion":"provision","book":"2 Corinthians","chapter":9,"verseStart":8,"verseEnd":8},{"id":"provision-psalm-34-10","reference":"Psalm 34:10","text":"The young lions do lack, and suffer hunger: but they that seek the Lord shall not want any good thing.","reflection":"Those who seek the Lord shall not lack any good thing, even when others go hungry.","emotion":"provision","book":"Psalms","chapter":34,"verseStart":10,"verseEnd":10},{"id":"provision-matthew-7-11","reference":"Matthew 7:11","text":"If ye then, being evil, know how to give good gifts unto your children, how much more shall your Father which is in heaven give good things to them that ask him?","reflection":"If imperfect parents give good gifts, how much more will your Father in heaven give to you?","emotion":"provision","book":"Matthew","chapter":7,"verseStart":11,"verseEnd":11},{"id":"provision-psalm-84-11","reference":"Psalm 84:11","text":"For the Lord God is a sun and shield: the Lord will give grace and glory: no good thing will he withhold from them that walk uprightly.","reflection":"The Lord gives grace and glory; no good thing does He withhold from those who walk uprightly.","emotion":"provision","book":"Psalms","chapter":84,"verseStart":11,"verseEnd":11}],"heartbroken":[{"id":"heartbroken-psalm-34-18","reference":"Psalm 34:18","text":"The Lord is nigh unto them that are of a broken heart; and saveth such as be of a contrite spirit.","reflection":"The Lord is near to the brokenhearted and saves the crushed in spirit. He is close right now.","emotion":"heartbroken","book":"Psalms","chapter":34,"verseStart":18,"verseEnd":18},{"id":"heartbroken-psalm-147-3","reference":"Psalm 147:3","text":"He healeth the broken in heart, and bindeth up their wounds.","reflection":"He heals the brokenhearted and binds up their wounds with tenderness.","emotion":"heartbroken","book":"Psalms","chapter":147,"verseStart":3,"verseEnd":3},{"id":"heartbroken-psalm-55-22","reference":"Psalm 55:22","text":"Cast thy burden upon the Lord, and he shall sustain thee: he shall never suffer the righteous to be moved.","reflection":"Cast this heavy burden on the Lord, and He will sustain you through the ache.","emotion":"heartbroken","book":"Psalms","chapter":55,"verseStart":22,"verseEnd":22},{"id":"heartbroken-john-14-1","reference":"John 14:1","text":"Let not your heart be troubled: ye believe in God, believe also in me.","reflection":"Let not your heart be troubled — believe in God, and believe also in Jesus.","emotion":"heartbroken","book":"John","chapter":14,"verseStart":1,"verseEnd":1},{"id":"heartbroken-psalm-27-10","reference":"Psalm 27:10","text":"When my father and my mother forsake me, then the Lord will take me up.","reflection":"Even if those you love forsake you, the Lord will take you up and hold you close.","emotion":"heartbroken","book":"Psalms","chapter":27,"verseStart":10,"verseEnd":10},{"id":"heartbroken-isaiah-61-1","reference":"Isaiah 61:1","text":"The Spirit of the Lord God is upon me; because the Lord hath anointed me to preach good tidings unto the meek; he hath sent me to bind up the brokenhearted, to proclaim liberty to the captives, and the opening of the prison to them that are bound;","reflection":"Jesus came to bind up the brokenhearted and to bring good news to the hurting.","emotion":"heartbroken","book":"Isaiah","chapter":61,"verseStart":1,"verseEnd":1},{"id":"heartbroken-psalm-73-26","reference":"Psalm 73:26","text":"My flesh and my heart faileth: but God is the strength of my heart, and my portion for ever.","reflection":"Though your heart and flesh fail, God is the strength of your heart and your portion forever.","emotion":"heartbroken","book":"Psalms","chapter":73,"verseStart":26,"verseEnd":26},{"id":"heartbroken-matthew-11-28-29","reference":"Matthew 11:28-29","text":"Come unto me, all ye that labour and are heavy laden, and I will give you rest. Take my yoke upon you, and learn of me; for I am meek and lowly in heart: and ye shall find rest unto your souls.","reflection":"Come to Jesus with your weary, wounded heart, and you will find rest for your soul.","emotion":"heartbroken","book":"Matthew","chapter":11,"verseStart":28,"verseEnd":29},{"id":"heartbroken-romans-8-28","reference":"Romans 8:28","text":"And we know that all things work together for good to them that love God, to them who are the called according to his purpose.","reflection":"God can weave even this heartbreak into something good for those who love Him.","emotion":"heartbroken","book":"Romans","chapter":8,"verseStart":28,"verseEnd":28},{"id":"heartbroken-psalm-30-5","reference":"Psalm 30:5","text":"For his anger endureth but a moment; in his favour is life: weeping may endure for a night, but joy cometh in the morning.","reflection":"Weeping may stay for the night, but joy comes in the morning. This night will not last forever.","emotion":"heartbroken","book":"Psalms","chapter":30,"verseStart":5,"verseEnd":5},{"id":"heartbroken-1-peter-5-7","reference":"1 Peter 5:7","text":"Casting all your care upon him; for he careth for you.","reflection":"Cast all your anxiety and pain on Him, because He genuinely cares for you.","emotion":"heartbroken","book":"1 Peter","chapter":5,"verseStart":7,"verseEnd":7},{"id":"heartbroken-psalm-51-17","reference":"Psalm 51:17","text":"The sacrifices of God are a broken spirit: a broken and a contrite heart, O God, thou wilt not despise.","reflection":"A broken and contrite heart God will not despise — He receives it tenderly.","emotion":"heartbroken","book":"Psalms","chapter":51,"verseStart":17,"verseEnd":17}],"wronged":[{"id":"wronged-romans-12-19","reference":"Romans 12:19","text":"Dearly beloved, avenge not yourselves, but rather give place unto wrath: for it is written, Vengeance is mine; I will repay, saith the Lord.","reflection":"Do not avenge yourselves; leave room for God’s justice, for vengeance belongs to Him.","emotion":"wronged","book":"Romans","chapter":12,"verseStart":19,"verseEnd":19},{"id":"wronged-1-peter-2-23","reference":"1 Peter 2:23","text":"Who, when he was reviled, reviled not again; when he suffered, he threatened not; but committed himself to him that judgeth righteously:","reflection":"When reviled, Jesus did not retaliate but entrusted Himself to God who judges justly. So can you.","emotion":"wronged","book":"1 Peter","chapter":2,"verseStart":23,"verseEnd":23},{"id":"wronged-matthew-5-44","reference":"Matthew 5:44","text":"But I say unto you, Love your enemies, bless them that curse you, do good to them that hate you, and pray for them which despitefully use you, and persecute you;","reflection":"Love your enemies and pray for those who mistreat you — a hard freedom that breaks the cycle.","emotion":"wronged","book":"Matthew","chapter":5,"verseStart":44,"verseEnd":44},{"id":"wronged-romans-12-17-18","reference":"Romans 12:17-18","text":"Recompense to no man evil for evil. Provide things honest in the sight of all men. If it be possible, as much as lieth in you, live peaceably with all men.","reflection":"Repay no one evil for evil; as far as it depends on you, live peaceably with all.","emotion":"wronged","book":"Romans","chapter":12,"verseStart":17,"verseEnd":18},{"id":"wronged-proverbs-20-22","reference":"Proverbs 20:22","text":"Say not thou, I will recompense evil; but wait on the Lord, and he shall save thee.","reflection":"Do not say, \"I will repay evil\"; wait for the Lord, and He will deliver you.","emotion":"wronged","book":"Proverbs","chapter":20,"verseStart":22,"verseEnd":22},{"id":"wronged-1-peter-3-9","reference":"1 Peter 3:9","text":"Not rendering evil for evil, or railing for railing: but contrariwise blessing; knowing that ye are thereunto called, that ye should inherit a blessing.","reflection":"Do not return evil for evil, but bless — for to this you were called, that you may inherit a blessing.","emotion":"wronged","book":"1 Peter","chapter":3,"verseStart":9,"verseEnd":9},{"id":"wronged-psalm-34-17","reference":"Psalm 34:17","text":"The righteous cry, and the Lord heareth, and delivereth them out of all their troubles.","reflection":"When the righteous cry out, the Lord hears and delivers them from all their troubles.","emotion":"wronged","book":"Psalms","chapter":34,"verseStart":17,"verseEnd":17},{"id":"wronged-isaiah-54-17","reference":"Isaiah 54:17","text":"No weapon that is formed against thee shall prosper; and every tongue that shall rise against thee in judgment thou shalt condemn. This is the heritage of the servants of the Lord, and their righteousness is of me, saith the Lord.","reflection":"No weapon formed against you shall prosper — this is the heritage of the servants of the Lord.","emotion":"wronged","book":"Isaiah","chapter":54,"verseStart":17,"verseEnd":17},{"id":"wronged-genesis-50-20","reference":"Genesis 50:20","text":"But as for you, ye thought evil against me; but God meant it unto good, to bring to pass, as it is this day, to save much people alive.","reflection":"What others meant for evil, God can mean for good, as He did for Joseph.","emotion":"wronged","book":"Genesis","chapter":50,"verseStart":20,"verseEnd":20},{"id":"wronged-luke-6-27-28","reference":"Luke 6:27-28","text":"But I say unto you which hear, Love your enemies, do good to them which hate you, Bless them that curse you, and pray for them which despitefully use you.","reflection":"Do good to those who hate you, and pray for those who abuse you — the path Jesus walked.","emotion":"wronged","book":"Luke","chapter":6,"verseStart":27,"verseEnd":28},{"id":"wronged-romans-12-21","reference":"Romans 12:21","text":"Be not overcome of evil, but overcome evil with good.","reflection":"Do not be overcome by evil, but overcome evil with good.","emotion":"wronged","book":"Romans","chapter":12,"verseStart":21,"verseEnd":21},{"id":"wronged-psalm-9-9","reference":"Psalm 9:9","text":"The Lord also will be a refuge for the oppressed, a refuge in times of trouble.","reflection":"The Lord is a refuge for the oppressed, a stronghold in times of trouble.","emotion":"wronged","book":"Psalms","chapter":9,"verseStart":9,"verseEnd":9}],"deciding":[{"id":"deciding-proverbs-3-5-6","reference":"Proverbs 3:5-6","text":"Trust in the Lord with all thine heart; and lean not unto thine own understanding. In all thy ways acknowledge him, and he shall direct thy paths.","reflection":"Trust the Lord with all your heart, and in all your ways acknowledge Him; He will direct your paths.","emotion":"deciding","book":"Proverbs","chapter":3,"verseStart":5,"verseEnd":6},{"id":"deciding-james-1-5","reference":"James 1:5","text":"If any of you lack wisdom, let him ask of God, that giveth to all men liberally, and upbraideth not; and it shall be given him.","reflection":"If you lack wisdom for this decision, ask God, who gives generously without reproach.","emotion":"deciding","book":"James","chapter":1,"verseStart":5,"verseEnd":5},{"id":"deciding-psalm-32-8","reference":"Psalm 32:8","text":"I will instruct thee and teach thee in the way which thou shalt go: I will guide thee with mine eye.","reflection":"God promises to instruct you and counsel you with His eye upon you. You are not deciding alone.","emotion":"deciding","book":"Psalms","chapter":32,"verseStart":8,"verseEnd":8},{"id":"deciding-proverbs-16-9","reference":"Proverbs 16:9","text":"A man’s heart deviseth his way: but the Lord directeth his steps.","reflection":"You make your plans, but the Lord directs your steps — you can move forward and trust Him with it.","emotion":"deciding","book":"Proverbs","chapter":16,"verseStart":9,"verseEnd":9},{"id":"deciding-isaiah-30-21","reference":"Isaiah 30:21","text":"And thine ears shall hear a word behind thee, saying, This is the way, walk ye in it, when ye turn to the right hand, and when ye turn to the left.","reflection":"You will hear His voice guiding: \"This is the way; walk in it.\"","emotion":"deciding","book":"Isaiah","chapter":30,"verseStart":21,"verseEnd":21},{"id":"deciding-jeremiah-29-11","reference":"Jeremiah 29:11","text":"For I know the thoughts that I think toward you, saith the Lord, thoughts of peace, and not of evil, to give you an expected end.","reflection":"God’s thoughts toward you are of peace and a future. He is invested in where you are going.","emotion":"deciding","book":"Jeremiah","chapter":29,"verseStart":11,"verseEnd":11},{"id":"deciding-psalm-37-23","reference":"Psalm 37:23","text":"The steps of a good man are ordered by the Lord: and he delighteth in his way.","reflection":"The steps of a good person are ordered by the Lord; He delights in their way.","emotion":"deciding","book":"Psalms","chapter":37,"verseStart":23,"verseEnd":23},{"id":"deciding-proverbs-16-3","reference":"Proverbs 16:3","text":"Commit thy works unto the Lord, and thy thoughts shall be established.","reflection":"Commit your works to the Lord, and your plans will be established.","emotion":"deciding","book":"Proverbs","chapter":16,"verseStart":3,"verseEnd":3},{"id":"deciding-psalm-25-4-5","reference":"Psalm 25:4-5","text":"Shew me thy ways, O Lord; teach me thy paths. Lead me in thy truth, and teach me: for thou art the God of my salvation; on thee do I wait all the day.","reflection":"Ask God to show you His ways and teach you His paths — a prayer for any crossroads.","emotion":"deciding","book":"Psalms","chapter":25,"verseStart":4,"verseEnd":5},{"id":"deciding-proverbs-11-14","reference":"Proverbs 11:14","text":"Where no counsel is, the people fall: but in the multitude of counsellors there is safety.","reflection":"In an abundance of wise counsel there is safety. Seek godly advice as you decide.","emotion":"deciding","book":"Proverbs","chapter":11,"verseStart":14,"verseEnd":14},{"id":"deciding-john-16-13","reference":"John 16:13","text":"Howbeit when he, the Spirit of truth, is come, he will guide you into all truth: for he shall not speak of himself; but whatsoever he shall hear, that shall he speak: and he will shew you things to come.","reflection":"The Spirit of truth will guide you into all truth. You have a Helper in this.","emotion":"deciding","book":"John","chapter":16,"verseStart":13,"verseEnd":13},{"id":"deciding-psalm-143-8","reference":"Psalm 143:8","text":"Cause me to hear thy lovingkindness in the morning; for in thee do I trust: cause me to know the way wherein I should walk; for I lift up my soul unto thee.","reflection":"Pray: \"Cause me to know the way I should walk, for I lift up my soul to you.\"","emotion":"deciding","book":"Psalms","chapter":143,"verseStart":8,"verseEnd":8}],"unsafe":[{"id":"unsafe-psalm-91-1-2","reference":"Psalm 91:1-2","text":"He that dwelleth in the secret place of the most High shall abide under the shadow of the Almighty. I will say of the Lord, He is my refuge and my fortress: my God; in him will I trust.","reflection":"Those who dwell in the shelter of the Most High abide in the shadow of the Almighty.","emotion":"unsafe","book":"Psalms","chapter":91,"verseStart":1,"verseEnd":2},{"id":"unsafe-psalm-121-7-8","reference":"Psalm 121:7-8","text":"The Lord shall preserve thee from all evil: he shall preserve thy soul. The Lord shall preserve thy going out and thy coming in from this time forth, and even for evermore.","reflection":"The Lord will keep you from all evil; He keeps your going out and coming in, now and forever.","emotion":"unsafe","book":"Psalms","chapter":121,"verseStart":7,"verseEnd":8},{"id":"unsafe-proverbs-18-10","reference":"Proverbs 18:10","text":"The name of the Lord is a strong tower: the righteous runneth into it, and is safe.","reflection":"The name of the Lord is a strong tower; the righteous run into it and are safe.","emotion":"unsafe","book":"Proverbs","chapter":18,"verseStart":10,"verseEnd":10},{"id":"unsafe-psalm-46-1","reference":"Psalm 46:1","text":"God is our refuge and strength, a very present help in trouble.","reflection":"God is your refuge and strength, a very present help in trouble.","emotion":"unsafe","book":"Psalms","chapter":46,"verseStart":1,"verseEnd":1},{"id":"unsafe-psalm-4-8","reference":"Psalm 4:8","text":"I will both lay me down in peace, and sleep: for thou, Lord, only makest me dwell in safety.","reflection":"You can lie down and sleep in peace, for the Lord alone makes you dwell in safety.","emotion":"unsafe","book":"Psalms","chapter":4,"verseStart":8,"verseEnd":8},{"id":"unsafe-2-thessalonians-3-3","reference":"2 Thessalonians 3:3","text":"But the Lord is faithful, who shall stablish you, and keep you from evil.","reflection":"The Lord is faithful; He will establish you and guard you against the evil one.","emotion":"unsafe","book":"2 Thessalonians","chapter":3,"verseStart":3,"verseEnd":3},{"id":"unsafe-psalm-27-1","reference":"Psalm 27:1","text":"The Lord is my light and my salvation; whom shall I fear? the Lord is the strength of my life; of whom shall I be afraid?","reflection":"The Lord is your light and your salvation — whom shall you fear?","emotion":"unsafe","book":"Psalms","chapter":27,"verseStart":1,"verseEnd":1},{"id":"unsafe-isaiah-41-10","reference":"Isaiah 41:10","text":"Fear thou not; for I am with thee: be not dismayed; for I am thy God: I will strengthen thee; yea, I will help thee; yea, I will uphold thee with the right hand of my righteousness.","reflection":"Fear not, for God is with you; He will strengthen and uphold you with His right hand.","emotion":"unsafe","book":"Isaiah","chapter":41,"verseStart":10,"verseEnd":10},{"id":"unsafe-psalm-23-4","reference":"Psalm 23:4","text":"Yea, though I walk through the valley of the shadow of death, I will fear no evil: for thou art with me; thy rod and thy staff they comfort me.","reflection":"Even through the darkest valley you need fear no evil, for He is with you.","emotion":"unsafe","book":"Psalms","chapter":23,"verseStart":4,"verseEnd":4},{"id":"unsafe-psalm-18-2","reference":"Psalm 18:2","text":"The Lord is my rock, and my fortress, and my deliverer; my God, my strength, in whom I will trust; my buckler, and the horn of my salvation, and my high tower.","reflection":"The Lord is your rock, your fortress, your deliverer, your shield, your stronghold.","emotion":"unsafe","book":"Psalms","chapter":18,"verseStart":2,"verseEnd":2},{"id":"unsafe-nahum-1-7","reference":"Nahum 1:7","text":"The Lord is good, a strong hold in the day of trouble; and he knoweth them that trust in him.","reflection":"The Lord is good, a stronghold in the day of trouble; He knows those who take refuge in Him.","emotion":"unsafe","book":"Nahum","chapter":1,"verseStart":7,"verseEnd":7},{"id":"unsafe-psalm-56-3-4","reference":"Psalm 56:3-4","text":"What time I am afraid, I will trust in thee. In God I will praise his word, in God I have put my trust; I will not fear what flesh can do unto me.","reflection":"When you are afraid, put your trust in God; what can mere flesh do to you?","emotion":"unsafe","book":"Psalms","chapter":56,"verseStart":3,"verseEnd":4}],"joyful":[{"id":"joyful-psalm-118-24","reference":"Psalm 118:24","text":"This is the day which the Lord hath made; we will rejoice and be glad in it.","reflection":"This is the day the Lord has made — rejoice and be glad in it. Joy can be a choice to see His goodness.","emotion":"joyful","book":"Psalms","chapter":118,"verseStart":24,"verseEnd":24},{"id":"joyful-philippians-4-4","reference":"Philippians 4:4","text":"Rejoice in the Lord alway: and again I say, Rejoice.","reflection":"Paul wrote \"rejoice always\" from prison — this joy is rooted in who God is, not in circumstances.","emotion":"joyful","book":"Philippians","chapter":4,"verseStart":4,"verseEnd":4},{"id":"joyful-nehemiah-8-10","reference":"Nehemiah 8:10","text":"Then he said unto them, Go your way, eat the fat, and drink the sweet, and send portions unto them for whom nothing is prepared: for this day is holy unto our Lord: neither be ye sorry; for the joy of the Lord is your strength.","reflection":"The joy of the Lord is your strength — not just a feeling, but a source of power.","emotion":"joyful","book":"Nehemiah","chapter":8,"verseStart":10,"verseEnd":10},{"id":"joyful-psalm-16-11","reference":"Psalm 16:11","text":"Thou wilt shew me the path of life: in thy presence is fulness of joy; at thy right hand there are pleasures for evermore.","reflection":"In God’s presence is fullness of joy, and pleasures forevermore at His right hand.","emotion":"joyful","book":"Psalms","chapter":16,"verseStart":11,"verseEnd":11},{"id":"joyful-psalm-37-4","reference":"Psalm 37:4","text":"Delight thyself also in the Lord; and he shall give thee the desires of thine heart.","reflection":"Delight yourself in the Lord, and He will give you the desires of your heart.","emotion":"joyful","book":"Psalms","chapter":37,"verseStart":4,"verseEnd":4},{"id":"joyful-john-15-11","reference":"John 15:11","text":"These things have I spoken unto you, that my joy might remain in you, and that your joy might be full.","reflection":"Jesus shares His words so that His joy may be in you and your joy may be full.","emotion":"joyful","book":"John","chapter":15,"verseStart":11,"verseEnd":11},{"id":"joyful-psalm-126-3","reference":"Psalm 126:3","text":"The Lord hath done great things for us; whereof we are glad.","reflection":"The Lord has done great things for us, and we are glad.","emotion":"joyful","book":"Psalms","chapter":126,"verseStart":3,"verseEnd":3},{"id":"joyful-romans-15-13","reference":"Romans 15:13","text":"Now the God of hope fill you with all joy and peace in believing, that ye may abound in hope, through the power of the Holy Ghost.","reflection":"May the God of hope fill you with all joy and peace in believing.","emotion":"joyful","book":"Romans","chapter":15,"verseStart":13,"verseEnd":13},{"id":"joyful-galatians-5-22-23","reference":"Galatians 5:22-23","text":"But the fruit of the Spirit is love, joy, peace, longsuffering, gentleness, goodness, faith, Meekness, temperance: against such there is no law.","reflection":"Joy is fruit of the Spirit — it grows in you as you walk with Him.","emotion":"joyful","book":"Galatians","chapter":5,"verseStart":22,"verseEnd":23},{"id":"joyful-psalm-28-7","reference":"Psalm 28:7","text":"The Lord is my strength and my shield; my heart trusted in him, and I am helped: therefore my heart greatly rejoiceth; and with my song will I praise him.","reflection":"The Lord is your strength and shield; your heart trusts Him, and you are helped and greatly rejoice.","emotion":"joyful","book":"Psalms","chapter":28,"verseStart":7,"verseEnd":7},{"id":"joyful-1-peter-1-8","reference":"1 Peter 1:8","text":"Whom having not seen, ye love; in whom, though now ye see him not, yet believing, ye rejoice with joy unspeakable and full of glory:","reflection":"Though you have not seen Him, you love Him and rejoice with joy inexpressible and full of glory.","emotion":"joyful","book":"1 Peter","chapter":1,"verseStart":8,"verseEnd":8},{"id":"joyful-psalm-30-11","reference":"Psalm 30:11","text":"Thou hast turned for me my mourning into dancing: thou hast put off my sackcloth, and girded me with gladness;","reflection":"God can turn your mourning into dancing and clothe you with gladness.","emotion":"joyful","book":"Psalms","chapter":30,"verseStart":11,"verseEnd":11}],"grateful":[{"id":"grateful-1-thessalonians-5-18","reference":"1 Thessalonians 5:18","text":"In every thing give thanks: for this is the will of God in Christ Jesus concerning you.","reflection":"In everything give thanks — this is God’s will for you. Thankfulness changes how you see everything.","emotion":"grateful","book":"1 Thessalonians","chapter":5,"verseStart":18,"verseEnd":18},{"id":"grateful-psalm-136-1","reference":"Psalm 136:1","text":"O give thanks unto the Lord; for he is good: for his mercy endureth for ever.","reflection":"Give thanks to the Lord, for He is good; His mercy endures forever.","emotion":"grateful","book":"Psalms","chapter":136,"verseStart":1,"verseEnd":1},{"id":"grateful-psalm-103-1-2","reference":"Psalm 103:1-2","text":"Bless the Lord, O my soul: and all that is within me, bless his holy name. Bless the Lord, O my soul, and forget not all his benefits:","reflection":"Bless the Lord, O my soul, and forget not all His benefits — gratitude is sometimes a discipline.","emotion":"grateful","book":"Psalms","chapter":103,"verseStart":1,"verseEnd":2},{"id":"grateful-james-1-17","reference":"James 1:17","text":"Every good gift and every perfect gift is from above, and cometh down from the Father of lights, with whom is no variableness, neither shadow of turning.","reflection":"Every good and perfect gift comes down from the Father; gratitude traces the gift back to the Giver.","emotion":"grateful","book":"James","chapter":1,"verseStart":17,"verseEnd":17},{"id":"grateful-psalm-100-4","reference":"Psalm 100:4","text":"Enter into his gates with thanksgiving, and into his courts with praise: be thankful unto him, and bless his name.","reflection":"Enter His gates with thanksgiving and His courts with praise — thankfulness is a doorway to His presence.","emotion":"grateful","book":"Psalms","chapter":100,"verseStart":4,"verseEnd":4},{"id":"grateful-colossians-3-15-17","reference":"Colossians 3:15-17","text":"And let the peace of God rule in your hearts, to the which also ye are called in one body; and be ye thankful. Let the word of Christ dwell in you richly in all wisdom; teaching and admonishing one another in psalms and hymns and spiritual songs, singing with grace in your hearts to the Lord. And whatsoever ye do in word or deed, do all in the name of the Lord Jesus, giving thanks to God and the Father by him.","reflection":"Let thankfulness fill your words and songs, doing everything in the name of the Lord Jesus.","emotion":"grateful","book":"Colossians","chapter":3,"verseStart":15,"verseEnd":17},{"id":"grateful-psalm-107-1","reference":"Psalm 107:1","text":"O give thanks unto the Lord, for he is good: for his mercy endureth for ever.","reflection":"Give thanks to the Lord, for He is good; His steadfast love endures forever.","emotion":"grateful","book":"Psalms","chapter":107,"verseStart":1,"verseEnd":1},{"id":"grateful-philippians-4-6","reference":"Philippians 4:6","text":"Be careful for nothing; but in every thing by prayer and supplication with thanksgiving let your requests be made known unto God.","reflection":"Bring your requests to God with thanksgiving — gratitude and prayer belong together.","emotion":"grateful","book":"Philippians","chapter":4,"verseStart":6,"verseEnd":6},{"id":"grateful-2-corinthians-9-15","reference":"2 Corinthians 9:15","text":"Thanks be unto God for his unspeakable gift.","reflection":"Thanks be to God for His indescribable gift — Jesus, the gift beyond all words.","emotion":"grateful","book":"2 Corinthians","chapter":9,"verseStart":15,"verseEnd":15},{"id":"grateful-psalm-9-1","reference":"Psalm 9:1","text":"I will praise thee, O Lord, with my whole heart; I will shew forth all thy marvellous works.","reflection":"Give thanks with your whole heart, and tell of all His wonderful deeds.","emotion":"grateful","book":"Psalms","chapter":9,"verseStart":1,"verseEnd":1},{"id":"grateful-ephesians-5-20","reference":"Ephesians 5:20","text":"Giving thanks always for all things unto God and the Father in the name of our Lord Jesus Christ;","reflection":"Give thanks always and for everything to God the Father in the name of our Lord Jesus.","emotion":"grateful","book":"Ephesians","chapter":5,"verseStart":20,"verseEnd":20},{"id":"grateful-1-chronicles-16-34","reference":"1 Chronicles 16:34","text":"O give thanks unto the Lord; for he is good; for his mercy endureth for ever.","reflection":"O give thanks to the Lord, for He is good; His love endures forever.","emotion":"grateful","book":"1 Chronicles","chapter":16,"verseStart":34,"verseEnd":34}],"hopeful":[{"id":"hopeful-jeremiah-29-11","reference":"Jeremiah 29:11","text":"For I know the thoughts that I think toward you, saith the Lord, thoughts of peace, and not of evil, to give you an expected end.","reflection":"God is thinking good thoughts toward your future — plans for peace, to give you hope and an end you long for.","emotion":"hopeful","book":"Jeremiah","chapter":29,"verseStart":11,"verseEnd":11},{"id":"hopeful-romans-15-13","reference":"Romans 15:13","text":"Now the God of hope fill you with all joy and peace in believing, that ye may abound in hope, through the power of the Holy Ghost.","reflection":"May the God of hope fill you with joy and peace, so you abound in hope by the Spirit’s power.","emotion":"hopeful","book":"Romans","chapter":15,"verseStart":13,"verseEnd":13},{"id":"hopeful-isaiah-40-31","reference":"Isaiah 40:31","text":"But they that wait upon the Lord shall renew their strength; they shall mount up with wings as eagles; they shall run, and not be weary; and they shall walk, and not faint.","reflection":"Those who wait on the Lord renew their strength and mount up with wings as eagles.","emotion":"hopeful","book":"Isaiah","chapter":40,"verseStart":31,"verseEnd":31},{"id":"hopeful-habakkuk-2-3","reference":"Habakkuk 2:3","text":"For the vision is yet for an appointed time, but at the end it shall speak, and not lie: though it tarry, wait for it; because it will surely come, it will not tarry.","reflection":"The vision is for an appointed time; though it tarry, wait for it — it will surely come.","emotion":"hopeful","book":"Habakkuk","chapter":2,"verseStart":3,"verseEnd":3},{"id":"hopeful-romans-8-28","reference":"Romans 8:28","text":"And we know that all things work together for good to them that love God, to them who are the called according to his purpose.","reflection":"Not some things — all things — God works together for good to those who love Him.","emotion":"hopeful","book":"Romans","chapter":8,"verseStart":28,"verseEnd":28},{"id":"hopeful-lamentations-3-21-23","reference":"Lamentations 3:21-23","text":"This I recall to my mind, therefore have I hope. It is of the Lord’s mercies that we are not consumed, because his compassions fail not. They are new every morning: great is thy faithfulness.","reflection":"This I recall and have hope: His mercies are new every morning; great is His faithfulness.","emotion":"hopeful","book":"Lamentations","chapter":3,"verseStart":21,"verseEnd":23},{"id":"hopeful-romans-5-3-5","reference":"Romans 5:3-5","text":"And not only so, but we glory in tribulations also: knowing that tribulation worketh patience; And patience, experience; and experience, hope: And hope maketh not ashamed; because the love of God is shed abroad in our hearts by the Holy Ghost which is given unto us.","reflection":"Suffering produces perseverance, character, and hope — and hope does not put us to shame.","emotion":"hopeful","book":"Romans","chapter":5,"verseStart":3,"verseEnd":5},{"id":"hopeful-hebrews-6-19","reference":"Hebrews 6:19","text":"Which hope we have as an anchor of the soul, both sure and stedfast, and which entereth into that within the veil;","reflection":"Hope is an anchor for the soul, firm and secure, reaching behind the veil to Christ Himself.","emotion":"hopeful","book":"Hebrews","chapter":6,"verseStart":19,"verseEnd":19},{"id":"hopeful-psalm-130-5","reference":"Psalm 130:5","text":"I wait for the Lord, my soul doth wait, and in his word do I hope.","reflection":"I wait for the Lord, my soul waits, and in His word I put my hope.","emotion":"hopeful","book":"Psalms","chapter":130,"verseStart":5,"verseEnd":5},{"id":"hopeful-micah-7-7","reference":"Micah 7:7","text":"Therefore I will look unto the Lord; I will wait for the God of my salvation: my God will hear me.","reflection":"As for me, I will look to the Lord; I will wait for the God of my salvation; my God will hear me.","emotion":"hopeful","book":"Micah","chapter":7,"verseStart":7,"verseEnd":7},{"id":"hopeful-proverbs-23-18","reference":"Proverbs 23:18","text":"For surely there is an end; and thine expectation shall not be cut off.","reflection":"Surely there is a future, and your hope will not be cut off.","emotion":"hopeful","book":"Proverbs","chapter":23,"verseStart":18,"verseEnd":18},{"id":"hopeful-psalm-31-24","reference":"Psalm 31:24","text":"Be of good courage, and he shall strengthen your heart, all ye that hope in the Lord.","reflection":"Be strong, and let your heart take courage, all you who hope in the Lord.","emotion":"hopeful","book":"Psalms","chapter":31,"verseStart":24,"verseEnd":24}],"peaceful":[{"id":"peaceful-numbers-6-24-26","reference":"Numbers 6:24-26","text":"The Lord bless thee, and keep thee: The Lord make his face shine upon thee, and be gracious unto thee: The Lord lift up his countenance upon thee, and give thee peace.","reflection":"This ancient blessing is spoken over you today: the Lord bless you, keep you, and give you peace.","emotion":"peaceful","book":"Numbers","chapter":6,"verseStart":24,"verseEnd":26},{"id":"peaceful-philippians-4-7","reference":"Philippians 4:7","text":"And the peace of God, which passeth all understanding, shall keep your hearts and minds through Christ Jesus.","reflection":"The peace of God, which surpasses understanding, will guard your heart and mind in Christ Jesus.","emotion":"peaceful","book":"Philippians","chapter":4,"verseStart":7,"verseEnd":7},{"id":"peaceful-psalm-23-1-3","reference":"Psalm 23:1-3","text":"The Lord is my shepherd; I shall not want. He maketh me to lie down in green pastures: he leadeth me beside the still waters. He restoreth my soul: he leadeth me in the paths of righteousness for his name’s sake.","reflection":"The Shepherd leads you to green pastures and still waters, and restores your soul.","emotion":"peaceful","book":"Psalms","chapter":23,"verseStart":1,"verseEnd":3},{"id":"peaceful-psalm-116-7","reference":"Psalm 116:7","text":"Return unto thy rest, O my soul; for the Lord hath dealt bountifully with thee.","reflection":"Return to your rest, O my soul, for the Lord has dealt bountifully with you.","emotion":"peaceful","book":"Psalms","chapter":116,"verseStart":7,"verseEnd":7},{"id":"peaceful-psalm-119-165","reference":"Psalm 119:165","text":"Great peace have they which love thy law: and nothing shall offend them.","reflection":"Great peace have those who love God’s law, and nothing makes them stumble.","emotion":"peaceful","book":"Psalms","chapter":119,"verseStart":165,"verseEnd":165},{"id":"peaceful-john-14-27","reference":"John 14:27","text":"Peace I leave with you, my peace I give unto you: not as the world giveth, give I unto you. Let not your heart be troubled, neither let it be afraid.","reflection":"Jesus gives a peace unlike the world’s — deep calm that holds even in chaos.","emotion":"peaceful","book":"John","chapter":14,"verseStart":27,"verseEnd":27},{"id":"peaceful-isaiah-26-3","reference":"Isaiah 26:3","text":"Thou wilt keep him in perfect peace, whose mind is stayed on thee: because he trusteth in thee.","reflection":"God keeps in perfect peace the one whose mind is fixed on Him, because they trust Him.","emotion":"peaceful","book":"Isaiah","chapter":26,"verseStart":3,"verseEnd":3},{"id":"peaceful-colossians-3-15","reference":"Colossians 3:15","text":"And let the peace of God rule in your hearts, to the which also ye are called in one body; and be ye thankful.","reflection":"Let the peace of Christ rule in your heart, to which you were called as one body.","emotion":"peaceful","book":"Colossians","chapter":3,"verseStart":15,"verseEnd":15},{"id":"peaceful-matthew-11-28-29","reference":"Matthew 11:28-29","text":"Come unto me, all ye that labour and are heavy laden, and I will give you rest. Take my yoke upon you, and learn of me; for I am meek and lowly in heart: and ye shall find rest unto your souls.","reflection":"Take Jesus’ gentle yoke, and you will find rest for your soul.","emotion":"peaceful","book":"Matthew","chapter":11,"verseStart":28,"verseEnd":29},{"id":"peaceful-psalm-4-8","reference":"Psalm 4:8","text":"I will both lay me down in peace, and sleep: for thou, Lord, only makest me dwell in safety.","reflection":"In peace you can lie down and sleep, for the Lord alone makes you dwell in safety.","emotion":"peaceful","book":"Psalms","chapter":4,"verseStart":8,"verseEnd":8},{"id":"peaceful-john-16-33","reference":"John 16:33","text":"These things I have spoken unto you, that in me ye might have peace. In the world ye shall have tribulation: but be of good cheer; I have overcome the world.","reflection":"In Christ you may have peace; in the world there is trouble, but He has overcome the world.","emotion":"peaceful","book":"John","chapter":16,"verseStart":33,"verseEnd":33},{"id":"peaceful-isaiah-32-17","reference":"Isaiah 32:17","text":"And the work of righteousness shall be peace; and the effect of righteousness quietness and assurance for ever.","reflection":"The fruit of righteousness is peace, and its effect quietness and trust forever.","emotion":"peaceful","book":"Isaiah","chapter":32,"verseStart":17,"verseEnd":17}],"courageous":[{"id":"courageous-joshua-1-9","reference":"Joshua 1:9","text":"Have not I commanded thee? Be strong and of a good courage; be not afraid, neither be thou dismayed: for the Lord thy God is with thee whithersoever thou goest.","reflection":"Be strong and courageous; do not be afraid, for the Lord your God is with you wherever you go.","emotion":"courageous","book":"Joshua","chapter":1,"verseStart":9,"verseEnd":9},{"id":"courageous-psalm-27-1","reference":"Psalm 27:1","text":"The Lord is my light and my salvation; whom shall I fear? the Lord is the strength of my life; of whom shall I be afraid?","reflection":"The Lord is your light and salvation and the strength of your life — whom shall you fear?","emotion":"courageous","book":"Psalms","chapter":27,"verseStart":1,"verseEnd":1},{"id":"courageous-isaiah-41-10","reference":"Isaiah 41:10","text":"Fear thou not; for I am with thee: be not dismayed; for I am thy God: I will strengthen thee; yea, I will help thee; yea, I will uphold thee with the right hand of my righteousness.","reflection":"Fear not, for God strengthens, helps, and upholds you with His righteous right hand.","emotion":"courageous","book":"Isaiah","chapter":41,"verseStart":10,"verseEnd":10},{"id":"courageous-deuteronomy-31-6","reference":"Deuteronomy 31:6","text":"Be strong and of a good courage, fear not, nor be afraid of them: for the Lord thy God, he it is that doth go with thee; he will not fail thee, nor forsake thee.","reflection":"Be strong and of good courage; the Lord goes with you and will not fail or forsake you.","emotion":"courageous","book":"Deuteronomy","chapter":31,"verseStart":6,"verseEnd":6},{"id":"courageous-1-corinthians-16-13","reference":"1 Corinthians 16:13","text":"Watch ye, stand fast in the faith, quit you like men, be strong.","reflection":"Watch, stand firm in the faith, be courageous, be strong.","emotion":"courageous","book":"1 Corinthians","chapter":16,"verseStart":13,"verseEnd":13},{"id":"courageous-2-timothy-1-7","reference":"2 Timothy 1:7","text":"For God hath not given us the spirit of fear; but of power, and of love, and of a sound mind.","reflection":"God gave you a spirit not of fear but of power, love, and a sound mind.","emotion":"courageous","book":"2 Timothy","chapter":1,"verseStart":7,"verseEnd":7},{"id":"courageous-ephesians-6-10","reference":"Ephesians 6:10","text":"Finally, my brethren, be strong in the Lord, and in the power of his might.","reflection":"Be strong in the Lord and in the strength of His might — the courage is His, given to you.","emotion":"courageous","book":"Ephesians","chapter":6,"verseStart":10,"verseEnd":10},{"id":"courageous-psalm-18-32-34","reference":"Psalm 18:32-34","text":"It is God that girdeth me with strength, and maketh my way perfect. He maketh my feet like hinds’ feet, and setteth me upon my high places. He teacheth my hands to war, so that a bow of steel is broken by mine arms.","reflection":"It is God who arms you with strength and makes your way secure, training your hands for the battle.","emotion":"courageous","book":"Psalms","chapter":18,"verseStart":32,"verseEnd":34},{"id":"courageous-proverbs-28-1","reference":"Proverbs 28:1","text":"The wicked flee when no man pursueth: but the righteous are bold as a lion.","reflection":"The righteous are as bold as a lion — boldness flows from a clean conscience before God.","emotion":"courageous","book":"Proverbs","chapter":28,"verseStart":1,"verseEnd":1},{"id":"courageous-1-chronicles-28-20","reference":"1 Chronicles 28:20","text":"And David said to Solomon his son, Be strong and of good courage, and do it: fear not, nor be dismayed: for the Lord God, even my God, will be with thee; he will not fail thee, nor forsake thee, until thou hast finished all the work for the service of the house of the Lord.","reflection":"Be strong and do the work; do not be afraid, for the Lord God is with you; He will not fail you.","emotion":"courageous","book":"1 Chronicles","chapter":28,"verseStart":20,"verseEnd":20},{"id":"courageous-psalm-138-3","reference":"Psalm 138:3","text":"In the day when I cried thou answeredst me, and strengthenedst me with strength in my soul.","reflection":"On the day you called, God answered and emboldened you with strength in your soul.","emotion":"courageous","book":"Psalms","chapter":138,"verseStart":3,"verseEnd":3},{"id":"courageous-joshua-1-7","reference":"Joshua 1:7","text":"Only be thou strong and very courageous, that thou mayest observe to do according to all the law, which Moses my servant commanded thee: turn not from it to the right hand or to the left, that thou mayest prosper whithersoever thou goest.","reflection":"Only be strong and very courageous, careful to walk in God’s word — and you will succeed.","emotion":"courageous","book":"Joshua","chapter":1,"verseStart":7,"verseEnd":7}],"loved":[{"id":"loved-john-3-16","reference":"John 3:16","text":"For God so loved the world, that he gave his only begotten Son, that whosoever believeth in him should not perish, but have everlasting life.","reflection":"God so loved the world — you included — that He gave His only Son, that you might have eternal life.","emotion":"loved","book":"John","chapter":3,"verseStart":16,"verseEnd":16},{"id":"loved-romans-8-38-39","reference":"Romans 8:38-39","text":"For I am persuaded, that neither death, nor life, nor angels, nor principalities, nor powers, nor things present, nor things to come, Nor height, nor depth, nor any other creature, shall be able to separate us from the love of God, which is in Christ Jesus our Lord.","reflection":"Nothing in all creation can separate you from the love of God in Christ Jesus.","emotion":"loved","book":"Romans","chapter":8,"verseStart":38,"verseEnd":39},{"id":"loved-1-john-4-9-10","reference":"1 John 4:9-10","text":"In this was manifested the love of God toward us, because that God sent his only begotten Son into the world, that we might live through him. Herein is love, not that we loved God, but that he loved us, and sent his Son to be the propitiation for our sins.","reflection":"This is love: not that we loved God, but that He loved us and sent His Son for us.","emotion":"loved","book":"1 John","chapter":4,"verseStart":9,"verseEnd":10},{"id":"loved-jeremiah-31-3","reference":"Jeremiah 31:3","text":"The Lord hath appeared of old unto me, saying, Yea, I have loved thee with an everlasting love: therefore with lovingkindness have I drawn thee.","reflection":"God says, \"I have loved you with an everlasting love; with lovingkindness I have drawn you.\"","emotion":"loved","book":"Jeremiah","chapter":31,"verseStart":3,"verseEnd":3},{"id":"loved-john-15-13","reference":"John 15:13","text":"Greater love hath no man than this, that a man lay down his life for his friends.","reflection":"Greater love has no one than this — and Jesus laid down His life for you, His friend.","emotion":"loved","book":"John","chapter":15,"verseStart":13,"verseEnd":13},{"id":"loved-ephesians-3-17-19","reference":"Ephesians 3:17-19","text":"That Christ may dwell in your hearts by faith; that ye, being rooted and grounded in love, May be able to comprehend with all saints what is the breadth, and length, and depth, and height; And to know the love of Christ, which passeth knowledge, that ye might be filled with all the fulness of God.","reflection":"May you grasp how wide, long, high, and deep the love of Christ is — a love beyond knowledge.","emotion":"loved","book":"Ephesians","chapter":3,"verseStart":17,"verseEnd":19},{"id":"loved-zephaniah-3-17","reference":"Zephaniah 3:17","text":"The Lord thy God in the midst of thee is mighty; he will save, he will rejoice over thee with joy; he will rest in his love, he will joy over thee with singing.","reflection":"The Lord your God is in your midst; He will rejoice over you with singing and quiet you with His love.","emotion":"loved","book":"Zephaniah","chapter":3,"verseStart":17,"verseEnd":17},{"id":"loved-1-john-3-1","reference":"1 John 3:1","text":"Behold, what manner of love the Father hath bestowed upon us, that we should be called the sons of God: therefore the world knoweth us not, because it knew him not.","reflection":"See what kind of love the Father has given, that you should be called a child of God — and you are.","emotion":"loved","book":"1 John","chapter":3,"verseStart":1,"verseEnd":1},{"id":"loved-romans-5-8","reference":"Romans 5:8","text":"But God commendeth his love toward us, in that, while we were yet sinners, Christ died for us.","reflection":"God shows His love in this: while we were still sinners, Christ died for us.","emotion":"loved","book":"Romans","chapter":5,"verseStart":8,"verseEnd":8},{"id":"loved-psalm-86-15","reference":"Psalm 86:15","text":"But thou, O Lord, art a God full of compassion, and gracious, longsuffering, and plenteous in mercy and truth.","reflection":"The Lord is merciful and gracious, slow to anger, abounding in steadfast love toward you.","emotion":"loved","book":"Psalms","chapter":86,"verseStart":15,"verseEnd":15},{"id":"loved-isaiah-43-4","reference":"Isaiah 43:4","text":"Since thou wast precious in my sight, thou hast been honourable, and I have loved thee: therefore will I give men for thee, and people for thy life.","reflection":"You are precious and honored in God’s eyes, and He loves you.","emotion":"loved","book":"Isaiah","chapter":43,"verseStart":4,"verseEnd":4},{"id":"loved-lamentations-3-22-23","reference":"Lamentations 3:22-23","text":"It is of the Lord’s mercies that we are not consumed, because his compassions fail not. They are new every morning: great is thy faithfulness.","reflection":"His steadfast love never ceases; His mercies are new every morning.","emotion":"loved","book":"Lamentations","chapter":3,"verseStart":22,"verseEnd":23}],"strong":[{"id":"strong-isaiah-40-29-31","reference":"Isaiah 40:29-31","text":"He giveth power to the faint; and to them that have no might he increaseth strength. Even the youths shall faint and be weary, and the young men shall utterly fall: But they that wait upon the Lord shall renew their strength; they shall mount up with wings as eagles; they shall run, and not be weary; and they shall walk, and not faint.","reflection":"He gives power to the faint; those who wait on the Lord renew their strength and do not grow weary.","emotion":"strong","book":"Isaiah","chapter":40,"verseStart":29,"verseEnd":31},{"id":"strong-philippians-4-13","reference":"Philippians 4:13","text":"I can do all things through Christ which strengtheneth me.","reflection":"You can do all things through Christ who strengthens you.","emotion":"strong","book":"Philippians","chapter":4,"verseStart":13,"verseEnd":13},{"id":"strong-2-corinthians-12-9-10","reference":"2 Corinthians 12:9-10","text":"And he said unto me, My grace is sufficient for thee: for my strength is made perfect in weakness. Most gladly therefore will I rather glory in my infirmities, that the power of Christ may rest upon me. Therefore I take pleasure in infirmities, in reproaches, in necessities, in persecutions, in distresses for Christ’s sake: for when I am weak, then am I strong.","reflection":"When you are weak, then you are strong, for His power rests on you in your weakness.","emotion":"strong","book":"2 Corinthians","chapter":12,"verseStart":9,"verseEnd":10},{"id":"strong-psalm-46-1","reference":"Psalm 46:1","text":"God is our refuge and strength, a very present help in trouble.","reflection":"God is your refuge and strength, a very present help in trouble.","emotion":"strong","book":"Psalms","chapter":46,"verseStart":1,"verseEnd":1},{"id":"strong-nehemiah-8-10","reference":"Nehemiah 8:10","text":"Then he said unto them, Go your way, eat the fat, and drink the sweet, and send portions unto them for whom nothing is prepared: for this day is holy unto our Lord: neither be ye sorry; for the joy of the Lord is your strength.","reflection":"The joy of the Lord is your strength — it holds you up when your own resolve runs out.","emotion":"strong","book":"Nehemiah","chapter":8,"verseStart":10,"verseEnd":10},{"id":"strong-ephesians-6-10","reference":"Ephesians 6:10","text":"Finally, my brethren, be strong in the Lord, and in the power of his might.","reflection":"Be strong in the Lord and in the power of His might.","emotion":"strong","book":"Ephesians","chapter":6,"verseStart":10,"verseEnd":10},{"id":"strong-psalm-18-1-2","reference":"Psalm 18:1-2","text":"I will love thee, O Lord, my strength. The Lord is my rock, and my fortress, and my deliverer; my God, my strength, in whom I will trust; my buckler, and the horn of my salvation, and my high tower.","reflection":"I love you, O Lord, my strength — my rock, my fortress, and my deliverer.","emotion":"strong","book":"Psalms","chapter":18,"verseStart":1,"verseEnd":2},{"id":"strong-isaiah-41-10","reference":"Isaiah 41:10","text":"Fear thou not; for I am with thee: be not dismayed; for I am thy God: I will strengthen thee; yea, I will help thee; yea, I will uphold thee with the right hand of my righteousness.","reflection":"God will strengthen you and help you and uphold you with His righteous right hand.","emotion":"strong","book":"Isaiah","chapter":41,"verseStart":10,"verseEnd":10},{"id":"strong-habakkuk-3-19","reference":"Habakkuk 3:19","text":"The Lord God is my strength, and he will make my feet like hinds’ feet, and he will make me to walk upon mine high places. To the chief singer on my stringed instruments.","reflection":"The Lord God is your strength; He makes your feet like the deer’s, able to tread the heights.","emotion":"strong","book":"Habakkuk","chapter":3,"verseStart":19,"verseEnd":19},{"id":"strong-psalm-73-26","reference":"Psalm 73:26","text":"My flesh and my heart faileth: but God is the strength of my heart, and my portion for ever.","reflection":"Though flesh and heart fail, God is the strength of your heart and your portion forever.","emotion":"strong","book":"Psalms","chapter":73,"verseStart":26,"verseEnd":26},{"id":"strong-1-corinthians-15-58","reference":"1 Corinthians 15:58","text":"Therefore, my beloved brethren, be ye stedfast, unmoveable, always abounding in the work of the Lord, forasmuch as ye know that your labour is not in vain in the Lord.","reflection":"Be steadfast, immovable, always abounding in the work of the Lord — your labour is not in vain.","emotion":"strong","book":"1 Corinthians","chapter":15,"verseStart":58,"verseEnd":58},{"id":"strong-2-timothy-4-7","reference":"2 Timothy 4:7","text":"I have fought a good fight, I have finished my course, I have kept the faith:","reflection":"\"I have fought the good fight, I have finished the race, I have kept the faith\" — a finish line worth pressing toward.","emotion":"strong","book":"2 Timothy","chapter":4,"verseStart":7,"verseEnd":7}],"purposeless":[{"id":"purposeless-jeremiah-29-11","reference":"Jeremiah 29:11","text":"For I know the thoughts that I think toward you, saith the Lord, thoughts of peace, and not of evil, to give you an expected end.","reflection":"God has plans for you — plans for peace and a future, not for harm. Your life has a direction in His hands.","emotion":"purposeless","book":"Jeremiah","chapter":29,"verseStart":11,"verseEnd":11},{"id":"purposeless-ephesians-2-10","reference":"Ephesians 2:10","text":"For we are his workmanship, created in Christ Jesus unto good works, which God hath before ordained that we should walk in them.","reflection":"You are God’s handiwork, created in Christ for good works prepared in advance for you to walk in.","emotion":"purposeless","book":"Ephesians","chapter":2,"verseStart":10,"verseEnd":10},{"id":"purposeless-romans-8-28","reference":"Romans 8:28","text":"And we know that all things work together for good to them that love God, to them who are the called according to his purpose.","reflection":"God works all things together for good for those who love Him and are called to His purpose.","emotion":"purposeless","book":"Romans","chapter":8,"verseStart":28,"verseEnd":28},{"id":"purposeless-psalm-139-13-16","reference":"Psalm 139:13-16","text":"For thou hast possessed my reins: thou hast covered me in my mother’s womb. I will praise thee; for I am fearfully and wonderfully made: marvellous are thy works; and that my soul knoweth right well. My substance was not hid from thee, when I was made in secret, and curiously wrought in the lowest parts of the earth. Thine eyes did see my substance, yet being unperfect; and in thy book all my members were written, which in continuance were fashioned, when as yet there was none of them.","reflection":"God formed you and wrote your days in His book before one of them came to be. You are not an accident.","emotion":"purposeless","book":"Psalms","chapter":139,"verseStart":13,"verseEnd":16},{"id":"purposeless-proverbs-19-21","reference":"Proverbs 19:21","text":"There are many devices in a man’s heart; nevertheless the counsel of the Lord, that shall stand.","reflection":"Many are the plans in a person’s heart, but the Lord’s purpose will stand.","emotion":"purposeless","book":"Proverbs","chapter":19,"verseStart":21,"verseEnd":21},{"id":"purposeless-philippians-1-6","reference":"Philippians 1:6","text":"Being confident of this very thing, that he which hath begun a good work in you will perform it until the day of Jesus Christ:","reflection":"He who began a good work in you will carry it to completion — your story is unfinished, not pointless.","emotion":"purposeless","book":"Philippians","chapter":1,"verseStart":6,"verseEnd":6},{"id":"purposeless-colossians-3-23-24","reference":"Colossians 3:23-24","text":"And whatsoever ye do, do it heartily, as to the Lord, and not unto men; Knowing that of the Lord ye shall receive the reward of the inheritance: for ye serve the Lord Christ.","reflection":"Whatever you do, work at it with all your heart for the Lord — ordinary work gains eternal meaning.","emotion":"purposeless","book":"Colossians","chapter":3,"verseStart":23,"verseEnd":24},{"id":"purposeless-esther-4-14","reference":"Esther 4:14","text":"For if thou altogether holdest thy peace at this time, then shall there enlargement and deliverance arise to the Jews from another place; but thou and thy father’s house shall be destroyed: and who knoweth whether thou art come to the kingdom for such a time as this?","reflection":"Perhaps you have come to your place \"for such a time as this.\" Your position is not random.","emotion":"purposeless","book":"Esther","chapter":4,"verseStart":14,"verseEnd":14},{"id":"purposeless-psalm-138-8","reference":"Psalm 138:8","text":"The Lord will perfect that which concerneth me: thy mercy, O Lord, endureth for ever: forsake not the works of thine own hands.","reflection":"The Lord will fulfill His purpose for you; His steadfast love endures forever.","emotion":"purposeless","book":"Psalms","chapter":138,"verseStart":8,"verseEnd":8},{"id":"purposeless-isaiah-43-7","reference":"Isaiah 43:7","text":"Even every one that is called by my name: for I have created him for my glory, I have formed him; yea, I have made him.","reflection":"You were created for God’s glory — formed and made by Him for a reason.","emotion":"purposeless","book":"Isaiah","chapter":43,"verseStart":7,"verseEnd":7},{"id":"purposeless-romans-12-2","reference":"Romans 12:2","text":"And be not conformed to this world: but be ye transformed by the renewing of your mind, that ye may prove what is that good, and acceptable, and perfect, will of God.","reflection":"Be transformed by the renewing of your mind, so you can discern God’s good and perfect will.","emotion":"purposeless","book":"Romans","chapter":12,"verseStart":2,"verseEnd":2}],"forgiven":[{"id":"forgiven-1-john-1-9","reference":"1 John 1:9","text":"If we confess our sins, he is faithful and just to forgive us our sins, and to cleanse us from all unrighteousness.","reflection":"If you confess your sins, He is faithful and just to forgive you and cleanse you from all unrighteousness.","emotion":"forgiven","book":"1 John","chapter":1,"verseStart":9,"verseEnd":9},{"id":"forgiven-romans-8-1","reference":"Romans 8:1","text":"There is therefore now no condemnation to them which are in Christ Jesus, who walk not after the flesh, but after the Spirit.","reflection":"There is now no condemnation for those who are in Christ Jesus. The case against you is closed.","emotion":"forgiven","book":"Romans","chapter":8,"verseStart":1,"verseEnd":1},{"id":"forgiven-psalm-103-12","reference":"Psalm 103:12","text":"As far as the east is from the west, so far hath he removed our transgressions from us.","reflection":"As far as the east is from the west, so far has He removed your transgressions from you.","emotion":"forgiven","book":"Psalms","chapter":103,"verseStart":12,"verseEnd":12},{"id":"forgiven-isaiah-43-25","reference":"Isaiah 43:25","text":"I, even I, am he that blotteth out thy transgressions for mine own sake, and will not remember thy sins.","reflection":"God blots out your transgressions for His own sake and remembers your sins no more.","emotion":"forgiven","book":"Isaiah","chapter":43,"verseStart":25,"verseEnd":25},{"id":"forgiven-micah-7-18-19","reference":"Micah 7:18-19","text":"Who is a God like unto thee, that pardoneth iniquity, and passeth by the transgression of the remnant of his heritage? he retaineth not his anger for ever, because he delighteth in mercy. He will turn again, he will have compassion upon us; he will subdue our iniquities; and thou wilt cast all their sins into the depths of the sea.","reflection":"God delights in mercy; He will tread your sins underfoot and cast them into the sea.","emotion":"forgiven","book":"Micah","chapter":7,"verseStart":18,"verseEnd":19},{"id":"forgiven-colossians-1-13-14","reference":"Colossians 1:13-14","text":"Who hath delivered us from the power of darkness, and hath translated us into the kingdom of his dear Son: In whom we have redemption through his blood, even the forgiveness of sins:","reflection":"You have been rescued from darkness and brought into His kingdom, with redemption and forgiveness.","emotion":"forgiven","book":"Colossians","chapter":1,"verseStart":13,"verseEnd":14},{"id":"forgiven-ephesians-1-7","reference":"Ephesians 1:7","text":"In whom we have redemption through his blood, the forgiveness of sins, according to the riches of his grace;","reflection":"In Christ you have redemption through His blood, the forgiveness of sins, according to His grace.","emotion":"forgiven","book":"Ephesians","chapter":1,"verseStart":7,"verseEnd":7},{"id":"forgiven-psalm-32-1","reference":"Psalm 32:1","text":"Blessed is he whose transgression is forgiven, whose sin is covered.","reflection":"Blessed is the one whose transgression is forgiven, whose sin is covered.","emotion":"forgiven","book":"Psalms","chapter":32,"verseStart":1,"verseEnd":1},{"id":"forgiven-hebrews-10-17","reference":"Hebrews 10:17","text":"And their sins and iniquities will I remember no more.","reflection":"God says, \"Their sins and lawless deeds I will remember no more.\" Forgiven means forgotten by Him.","emotion":"forgiven","book":"Hebrews","chapter":10,"verseStart":17,"verseEnd":17},{"id":"forgiven-2-corinthians-5-17","reference":"2 Corinthians 5:17","text":"Therefore if any man be in Christ, he is a new creature: old things are passed away; behold, all things are become new.","reflection":"If anyone is in Christ, they are a new creation; the old has gone, the new has come.","emotion":"forgiven","book":"2 Corinthians","chapter":5,"verseStart":17,"verseEnd":17},{"id":"forgiven-acts-3-19","reference":"Acts 3:19","text":"Repent ye therefore, and be converted, that your sins may be blotted out, when the times of refreshing shall come from the presence of the Lord;","reflection":"Repent and turn to God, that your sins may be blotted out and times of refreshing may come.","emotion":"forgiven","book":"Acts","chapter":3,"verseStart":19,"verseEnd":19},{"id":"forgiven-psalm-130-3-4","reference":"Psalm 130:3-4","text":"If thou, Lord, shouldest mark iniquities, O Lord, who shall stand? But there is forgiveness with thee, that thou mayest be feared.","reflection":"If God kept a record of sins, none could stand — but with Him there is forgiveness.","emotion":"forgiven","book":"Psalms","chapter":130,"verseStart":3,"verseEnd":4}],"forgiving":[{"id":"forgiving-ephesians-4-31-32","reference":"Ephesians 4:31-32","text":"Let all bitterness, and wrath, and anger, and clamour, and evil speaking, be put away from you, with all malice: And be ye kind one to another, tenderhearted, forgiving one another, even as God for Christ’s sake hath forgiven you.","reflection":"Put away bitterness and be kind, forgiving one another as God in Christ forgave you.","emotion":"forgiving","book":"Ephesians","chapter":4,"verseStart":31,"verseEnd":32},{"id":"forgiving-colossians-3-13","reference":"Colossians 3:13","text":"Forbearing one another, and forgiving one another, if any man have a quarrel against any: even as Christ forgave you, so also do ye.","reflection":"Bear with one another and forgive, as the Lord has forgiven you.","emotion":"forgiving","book":"Colossians","chapter":3,"verseStart":13,"verseEnd":13},{"id":"forgiving-matthew-6-14-15","reference":"Matthew 6:14-15","text":"For if ye forgive men their trespasses, your heavenly Father will also forgive you: But if ye forgive not men their trespasses, neither will your Father forgive your trespasses.","reflection":"If you forgive others, your heavenly Father will also forgive you.","emotion":"forgiving","book":"Matthew","chapter":6,"verseStart":14,"verseEnd":15},{"id":"forgiving-matthew-18-21-22","reference":"Matthew 18:21-22","text":"Then came Peter to him, and said, Lord, how oft shall my brother sin against me, and I forgive him? till seven times? Jesus saith unto him, I say not unto thee, Until seven times: but, Until seventy times seven.","reflection":"Not seven times, but seventy times seven — forgiveness is meant to be a way of life, not a one-time act.","emotion":"forgiving","book":"Matthew","chapter":18,"verseStart":21,"verseEnd":22},{"id":"forgiving-mark-11-25","reference":"Mark 11:25","text":"And when ye stand praying, forgive, if ye have ought against any: that your Father also which is in heaven may forgive you your trespasses.","reflection":"When you stand praying, forgive, so your Father may forgive you.","emotion":"forgiving","book":"Mark","chapter":11,"verseStart":25,"verseEnd":25},{"id":"forgiving-luke-23-34","reference":"Luke 23:34","text":"Then said Jesus, Father, forgive them; for they know not what they do. And they parted his raiment, and cast lots.","reflection":"From the cross Jesus prayed, \"Father, forgive them\" — the hardest forgiveness, modeled for us.","emotion":"forgiving","book":"Luke","chapter":23,"verseStart":34,"verseEnd":34},{"id":"forgiving-luke-6-37","reference":"Luke 6:37","text":"Judge not, and ye shall not be judged: condemn not, and ye shall not be condemned: forgive, and ye shall be forgiven:","reflection":"Do not judge, do not condemn, forgive — and you will be forgiven.","emotion":"forgiving","book":"Luke","chapter":6,"verseStart":37,"verseEnd":37},{"id":"forgiving-romans-12-19","reference":"Romans 12:19","text":"Dearly beloved, avenge not yourselves, but rather give place unto wrath: for it is written, Vengeance is mine; I will repay, saith the Lord.","reflection":"Leave room for God’s justice; you can release the debt because He will settle every account.","emotion":"forgiving","book":"Romans","chapter":12,"verseStart":19,"verseEnd":19},{"id":"forgiving-1-peter-4-8","reference":"1 Peter 4:8","text":"And above all things have fervent charity among yourselves: for charity shall cover the multitude of sins.","reflection":"Above all, love one another earnestly, since love covers a multitude of sins.","emotion":"forgiving","book":"1 Peter","chapter":4,"verseStart":8,"verseEnd":8},{"id":"forgiving-proverbs-17-9","reference":"Proverbs 17:9","text":"He that covereth a transgression seeketh love; but he that repeateth a matter separateth very friends.","reflection":"Whoever covers an offense seeks love, but whoever repeats a matter separates close friends.","emotion":"forgiving","book":"Proverbs","chapter":17,"verseStart":9,"verseEnd":9},{"id":"forgiving-matthew-5-44","reference":"Matthew 5:44","text":"But I say unto you, Love your enemies, bless them that curse you, do good to them that hate you, and pray for them which despitefully use you, and persecute you;","reflection":"Love your enemies and pray for those who persecute you — prayer often softens the heart that forgives.","emotion":"forgiving","book":"Matthew","chapter":5,"verseStart":44,"verseEnd":44},{"id":"forgiving-genesis-50-20","reference":"Genesis 50:20","text":"But as for you, ye thought evil against me; but God meant it unto good, to bring to pass, as it is this day, to save much people alive.","reflection":"Like Joseph, you can come to say: what was meant for evil, God meant for good.","emotion":"forgiving","book":"Genesis","chapter":50,"verseStart":20,"verseEnd":20}],"prayerless":[{"id":"prayerless-philippians-4-6-7","reference":"Philippians 4:6-7","text":"Be careful for nothing; but in every thing by prayer and supplication with thanksgiving let your requests be made known unto God. And the peace of God, which passeth all understanding, shall keep your hearts and minds through Christ Jesus.","reflection":"Pray about everything; bring your requests with thanksgiving, and His peace will guard you.","emotion":"prayerless","book":"Philippians","chapter":4,"verseStart":6,"verseEnd":7},{"id":"prayerless-matthew-6-6-8","reference":"Matthew 6:6-8","text":"But thou, when thou prayest, enter into thy closet, and when thou hast shut thy door, pray to thy Father which is in secret; and thy Father which seeth in secret shall reward thee openly. But when ye pray, use not vain repetitions, as the heathen do: for they think that they shall be heard for their much speaking. Be not ye therefore like unto them: for your Father knoweth what things ye have need of, before ye ask him.","reflection":"Prayer is not performance; go to your Father in secret, who already knows what you need.","emotion":"prayerless","book":"Matthew","chapter":6,"verseStart":6,"verseEnd":8},{"id":"prayerless-romans-8-26","reference":"Romans 8:26","text":"Likewise the Spirit also helpeth our infirmities: for we know not what we should pray for as we ought: but the Spirit itself maketh intercession for us with groanings which cannot be uttered.","reflection":"When you do not know what to pray, the Spirit Himself intercedes for you with groans words cannot express.","emotion":"prayerless","book":"Romans","chapter":8,"verseStart":26,"verseEnd":26},{"id":"prayerless-1-thessalonians-5-16-18","reference":"1 Thessalonians 5:16-18","text":"Rejoice evermore. Pray without ceasing. In every thing give thanks: for this is the will of God in Christ Jesus concerning you.","reflection":"Rejoice always, pray continually, give thanks — prayer can become the rhythm of your day.","emotion":"prayerless","book":"1 Thessalonians","chapter":5,"verseStart":16,"verseEnd":18},{"id":"prayerless-james-5-16","reference":"James 5:16","text":"Confess your faults one to another, and pray one for another, that ye may be healed. The effectual fervent prayer of a righteous man availeth much.","reflection":"The earnest prayer of a righteous person has great power and effect.","emotion":"prayerless","book":"James","chapter":5,"verseStart":16,"verseEnd":16},{"id":"prayerless-matthew-7-7","reference":"Matthew 7:7","text":"Ask, and it shall be given you; seek, and ye shall find; knock, and it shall be opened unto you:","reflection":"Ask and it will be given; seek and you will find; knock and the door will be opened.","emotion":"prayerless","book":"Matthew","chapter":7,"verseStart":7,"verseEnd":7},{"id":"prayerless-psalm-145-18","reference":"Psalm 145:18","text":"The Lord is nigh unto all them that call upon him, to all that call upon him in truth.","reflection":"The Lord is near to all who call on Him, to all who call on Him in truth.","emotion":"prayerless","book":"Psalms","chapter":145,"verseStart":18,"verseEnd":18},{"id":"prayerless-jeremiah-29-12","reference":"Jeremiah 29:12","text":"Then shall ye call upon me, and ye shall go and pray unto me, and I will hearken unto you.","reflection":"You will call on Him and come and pray to Him, and He will listen to you.","emotion":"prayerless","book":"Jeremiah","chapter":29,"verseStart":12,"verseEnd":12},{"id":"prayerless-luke-11-9-10","reference":"Luke 11:9-10","text":"And I say unto you, Ask, and it shall be given you; seek, and ye shall find; knock, and it shall be opened unto you. For every one that asketh receiveth; and he that seeketh findeth; and to him that knocketh it shall be opened.","reflection":"Everyone who asks receives, and the one who seeks finds — keep coming to Him.","emotion":"prayerless","book":"Luke","chapter":11,"verseStart":9,"verseEnd":10},{"id":"prayerless-hebrews-4-16","reference":"Hebrews 4:16","text":"Let us therefore come boldly unto the throne of grace, that we may obtain mercy, and find grace to help in time of need.","reflection":"Come boldly to the throne of grace, to receive mercy and find grace to help in time of need.","emotion":"prayerless","book":"Hebrews","chapter":4,"verseStart":16,"verseEnd":16},{"id":"prayerless-john-15-7","reference":"John 15:7","text":"If ye abide in me, and my words abide in you, ye shall ask what ye will, and it shall be done unto you.","reflection":"If you abide in Christ and His words abide in you, ask what you wish, and it will be done.","emotion":"prayerless","book":"John","chapter":15,"verseStart":7,"verseEnd":7},{"id":"prayerless-psalm-62-8","reference":"Psalm 62:8","text":"Trust in him at all times; ye people, pour out your heart before him: God is a refuge for us. Selah.","reflection":"Trust in Him at all times; pour out your heart before Him, for God is a refuge for us.","emotion":"prayerless","book":"Psalms","chapter":62,"verseStart":8,"verseEnd":8}],"worshipful":[{"id":"worshipful-psalm-100-1-2","reference":"Psalm 100:1-2","text":"Make a joyful noise unto the Lord, all ye lands. Serve the Lord with gladness: come before his presence with singing.","reflection":"Make a joyful noise to the Lord; serve Him with gladness and come before Him with singing.","emotion":"worshipful","book":"Psalms","chapter":100,"verseStart":1,"verseEnd":2},{"id":"worshipful-psalm-95-1-2","reference":"Psalm 95:1-2","text":"O come, let us sing unto the Lord: let us make a joyful noise to the rock of our salvation. Let us come before his presence with thanksgiving, and make a joyful noise unto him with psalms.","reflection":"Come, let us sing to the Lord and shout joyfully to the Rock of our salvation.","emotion":"worshipful","book":"Psalms","chapter":95,"verseStart":1,"verseEnd":2},{"id":"worshipful-psalm-150-6","reference":"Psalm 150:6","text":"Let every thing that hath breath praise the Lord. Praise ye the Lord.","reflection":"Let everything that has breath praise the Lord. Praise the Lord!","emotion":"worshipful","book":"Psalms","chapter":150,"verseStart":6,"verseEnd":6},{"id":"worshipful-psalm-34-1","reference":"Psalm 34:1","text":"I will bless the Lord at all times: his praise shall continually be in my mouth.","reflection":"I will bless the Lord at all times; His praise shall continually be in my mouth.","emotion":"worshipful","book":"Psalms","chapter":34,"verseStart":1,"verseEnd":1},{"id":"worshipful-psalm-103-1","reference":"Psalm 103:1","text":"Bless the Lord, O my soul: and all that is within me, bless his holy name.","reflection":"Bless the Lord, O my soul, and all that is within me, bless His holy name.","emotion":"worshipful","book":"Psalms","chapter":103,"verseStart":1,"verseEnd":1},{"id":"worshipful-john-4-24","reference":"John 4:24","text":"God is a Spirit: and they that worship him must worship him in spirit and in truth.","reflection":"God is spirit, and those who worship Him must worship in spirit and in truth.","emotion":"worshipful","book":"John","chapter":4,"verseStart":24,"verseEnd":24},{"id":"worshipful-psalm-96-1-2","reference":"Psalm 96:1-2","text":"O sing unto the Lord a new song: sing unto the Lord, all the earth. Sing unto the Lord, bless his name; shew forth his salvation from day to day.","reflection":"Sing to the Lord a new song; sing to the Lord, all the earth; bless His name.","emotion":"worshipful","book":"Psalms","chapter":96,"verseStart":1,"verseEnd":2},{"id":"worshipful-psalm-145-3","reference":"Psalm 145:3","text":"Great is the Lord, and greatly to be praised; and his greatness is unsearchable.","reflection":"Great is the Lord and greatly to be praised; His greatness is unsearchable.","emotion":"worshipful","book":"Psalms","chapter":145,"verseStart":3,"verseEnd":3},{"id":"worshipful-revelation-4-11","reference":"Revelation 4:11","text":"Thou art worthy, O Lord, to receive glory and honour and power: for thou hast created all things, and for thy pleasure they are and were created.","reflection":"Worthy are You, our Lord and God, to receive glory and honor and power.","emotion":"worshipful","book":"Revelation","chapter":4,"verseStart":11,"verseEnd":11},{"id":"worshipful-hebrews-13-15","reference":"Hebrews 13:15","text":"By him therefore let us offer the sacrifice of praise to God continually, that is, the fruit of our lips giving thanks to his name.","reflection":"Through Jesus, continually offer a sacrifice of praise — the fruit of lips that confess His name.","emotion":"worshipful","book":"Hebrews","chapter":13,"verseStart":15,"verseEnd":15},{"id":"worshipful-psalm-63-3-4","reference":"Psalm 63:3-4","text":"Because thy lovingkindness is better than life, my lips shall praise thee. Thus will I bless thee while I live: I will lift up my hands in thy name.","reflection":"Because His lovingkindness is better than life, your lips will praise Him; you will bless Him while you live.","emotion":"worshipful","book":"Psalms","chapter":63,"verseStart":3,"verseEnd":4},{"id":"worshipful-psalm-29-2","reference":"Psalm 29:2","text":"Give unto the Lord the glory due unto his name; worship the Lord in the beauty of holiness.","reflection":"Give to the Lord the glory due His name; worship the Lord in the beauty of holiness.","emotion":"worshipful","book":"Psalms","chapter":29,"verseStart":2,"verseEnd":2}],"numb":[{"id":"numb-psalm-42-1-2","reference":"Psalm 42:1-2","text":"As the hart panteth after the water brooks, so panteth my soul after thee, O God. My soul thirsteth for God, for the living God: when shall I come and appear before God?","reflection":"As the deer pants for water, so your soul thirsts for God — even this longing is a sign of life.","emotion":"numb","book":"Psalms","chapter":42,"verseStart":1,"verseEnd":2},{"id":"numb-psalm-13-1-2","reference":"Psalm 13:1-2","text":"How long wilt thou forget me, O Lord? for ever? how long wilt thou hide thy face from me? How long shall I take counsel in my soul, having sorrow in my heart daily? how long shall mine enemy be exalted over me?","reflection":"The honest cry \"How long, O Lord, will you forget me?\" is in the Bible — God can handle your raw questions.","emotion":"numb","book":"Psalms","chapter":13,"verseStart":1,"verseEnd":2},{"id":"numb-lamentations-3-22-23","reference":"Lamentations 3:22-23","text":"It is of the Lord’s mercies that we are not consumed, because his compassions fail not. They are new every morning: great is thy faithfulness.","reflection":"Even when you feel nothing, His mercies are new every morning; His faithfulness does not depend on your feelings.","emotion":"numb","book":"Lamentations","chapter":3,"verseStart":22,"verseEnd":23},{"id":"numb-psalm-63-1","reference":"Psalm 63:1","text":"O God, thou art my God; early will I seek thee: my soul thirsteth for thee, my flesh longeth for thee in a dry and thirsty land, where no water is;","reflection":"O God, you are my God; earnestly I seek you in a dry and weary land where there is no water.","emotion":"numb","book":"Psalms","chapter":63,"verseStart":1,"verseEnd":1},{"id":"numb-isaiah-40-31","reference":"Isaiah 40:31","text":"But they that wait upon the Lord shall renew their strength; they shall mount up with wings as eagles; they shall run, and not be weary; and they shall walk, and not faint.","reflection":"Those who wait on the Lord will renew their strength — the dry season is not the end.","emotion":"numb","book":"Isaiah","chapter":40,"verseStart":31,"verseEnd":31},{"id":"numb-psalm-51-10-12","reference":"Psalm 51:10-12","text":"Create in me a clean heart, O God; and renew a right spirit within me. Cast me not away from thy presence; and take not thy holy spirit from me. Restore unto me the joy of thy salvation; and uphold me with thy free spirit.","reflection":"Pray: \"Restore to me the joy of your salvation\" — it is God’s to give back.","emotion":"numb","book":"Psalms","chapter":51,"verseStart":10,"verseEnd":12},{"id":"numb-hosea-6-1-3","reference":"Hosea 6:1-3","text":"Come, and let us return unto the Lord: for he hath torn, and he will heal us; he hath smitten, and he will bind us up. After two days will he revive us: in the third day he will raise us up, and we shall live in his sight. Then shall we know, if we follow on to know the Lord: his going forth is prepared as the morning; and he shall come unto us as the rain, as the latter and former rain unto the earth.","reflection":"Return to the Lord; as surely as the dawn, He will come to you like the spring rains.","emotion":"numb","book":"Hosea","chapter":6,"verseStart":1,"verseEnd":3},{"id":"numb-psalm-143-6","reference":"Psalm 143:6","text":"I stretch forth my hands unto thee: my soul thirsteth after thee, as a thirsty land. Selah.","reflection":"Stretch out your hands to Him; let your soul thirst for Him like a parched land.","emotion":"numb","book":"Psalms","chapter":143,"verseStart":6,"verseEnd":6},{"id":"numb-revelation-3-20","reference":"Revelation 3:20","text":"Behold, I stand at the door, and knock: if any man hear my voice, and open the door, I will come in to him, and will sup with him, and he with me.","reflection":"Jesus stands at the door and knocks; if you open even a little, He will come in.","emotion":"numb","book":"Revelation","chapter":3,"verseStart":20,"verseEnd":20},{"id":"numb-psalm-73-26","reference":"Psalm 73:26","text":"My flesh and my heart faileth: but God is the strength of my heart, and my portion for ever.","reflection":"Though your heart feels like stone, God remains the strength of your heart and your portion.","emotion":"numb","book":"Psalms","chapter":73,"verseStart":26,"verseEnd":26},{"id":"numb-jeremiah-29-13","reference":"Jeremiah 29:13","text":"And ye shall seek me, and find me, when ye shall search for me with all your heart.","reflection":"You will seek Him and find Him when you search for Him with all your heart.","emotion":"numb","book":"Jeremiah","chapter":29,"verseStart":13,"verseEnd":13},{"id":"numb-psalm-30-11-12","reference":"Psalm 30:11-12","text":"Thou hast turned for me my mourning into dancing: thou hast put off my sackcloth, and girded me with gladness; To the end that my glory may sing praise to thee, and not be silent. O Lord my God, I will give thanks unto thee for ever.","reflection":"God can turn mourning into dancing again — the numbness is not your forever.","emotion":"numb","book":"Psalms","chapter":30,"verseStart":11,"verseEnd":12}]};

export const allCuratedVerses: CuratedVerse[] = Object.values(versesByEmotion).flat();

export const uniqueCuratedVerses: CuratedVerse[] = (() => {
  const seen = new Set<string>();
  const out: CuratedVerse[] = [];
  for (const v of allCuratedVerses) { if (!seen.has(v.reference)) { seen.add(v.reference); out.push(v); } }
  return out;
})();
